### CF1061C  Multiplicity

##### 题目

从序列 $\{a_1,\ a_2,\ ..\ ,\ a_n\}$ 中选出**非空**子序列 $\{b_1,\ b_2,\ ..\ ,\ b_k\}$，一个子序列合法需要满足 $\forall\ i \in [1,\ k],\ i\ |\ b_i$。求有多少互不相等的合法子序列，答案对 $10^9 + 7$ 取模。

序列 $\{1,\ 1\}$ 有 $2$ 种选法得到子序列 $\{1\}$，但 $1$ 的来源不同，认为这两个子序列不相等。

##### 思路

$f[x][k]$表示从序列的前x位选k个的方案数

$f[x][k]$从哪里来？

第x位要不要选做子序列的第k个？

则有$f[x-1][k]$和,$f[x-1][k-1]$中转移过来

那么我们就有
$
f[x][y]=
\begin{cases}
f[x-1][y]+f[x-1][y-1],&y|a[i] \\
f[x-1][y] &otherwise
\end{cases}
$
发现$x$由$x-1$唯一确定

可以加一个滚动数组优化

于是代码框架是：外层枚举x，内层枚举y进行转移

现在来优化时间，考虑内层循环的次数，我们知道，只有当$y|a[x]$的那些y才需要特殊考虑，于是因数分解$a[x]$

总的复杂度$O(n\sqrt{n})$

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <string>
#include <cstring>
#include <vector>
using namespace std;
const int mod=1e9+7;
const int maxn=100005;
int n;
int a[maxn];
int f[maxn];
vector <int> fac;
void get_factor(int x)
{
	for(int i=1;i*i<=x;i++)
	{
		if(x%i==0)
		{
			fac.push_back(i);
			if(x!=i*i)
			fac.push_back(x/i);
		}
	}
	sort(fac.begin(),fac.end(),greater<int>());
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	cin>>a[i];
	f[0]=1;
	for(int i=1;i<=n;i++)
	{
		get_factor(a[i]);
		for(auto j:fac)
		{
			if(j<=i)
			f[j]=(f[j]+f[j-1])%mod;
		}
		fac.clear();
	}
	int ans=0;
	for(int i=1;i<=n;i++)
	ans=(ans+f[i])%mod;
	cout<<ans<<'\n';
	return 0;
}
```

### P1004 方格取数

##### 思路

两个人同时走和先后走是一样的结果，只要保证每个数只被取到一次

设计$f[step][a][b][x][y]$表示两个人各走$step$步，第一个人走到$(a,b)$，第二个人走到$(x,y)$能获取的最大价值

有
$
f[step][a][b][x][y]=benifit+max 
\begin{cases}
f[step-1][a-1][b][x-1][y] \\
f[step-1][a-1][b][x][y-1] \\
f[step-1][a][b-1][x-1][y] \\
f[step-1][a][b-1][x][y-1] \\
\end{cases}
$

然后发现根据滚动数组，可以$step$这一层滚掉，不难写出代码

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <string>
#include <cstring>
using namespace std;
const int N=15;
int n;
int w[N][N];
int f[N*2][N][N];
int main()
{
	memset(w,0,sizeof(w));
	cin>>n;
	while(1)
	{
		int x,y,z;
		cin>>x>>y>>z;
		if(x==0&&y==0&&z==0)
		break;
		w[x][y]=z;
	}
	memset(f,0,sizeof(f));
	for(int k=2;k<=n+n;k++)
	{
		for(int x1=max(1,k-n);x1<=min(k-1,n);x1++)
		{
			for(int x2=max(1,k-n);x2<=min(k-1,n);x2++)
			{
				int t=w[x1][k-x1];
				if(x1!=x2) t+=w[x2][k-x2];
				for(int a=0;a<=1;a++)
				{
					for(int b=0;b<=1;b++)
					f[k][x1][x2]=max(f[k][x1][x2],f[k-1][x1-a][x2-b]+t);
				}
			}
		}
	}
	cout<<f[2*n][n][n]<<endl;
	return 0; 
}
```

### CF245H Queries for Number of Palindromes

##### 思路

题意就是要统计l到r内的回文子串的个数

设答案为$f[l][r]$,根据容斥原理
$
f[l][r]=f[l][r-1]+f[l+1][r]-f[l+1][r-1]+ispal(s_{l\dots r})
$
其中is_pal可以$O(|s|^2)$预处理

所以整个问题可以在$O(|s|^2)$的时间内解决

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <string>
#include <cstring>
using namespace std;
const int maxn=5005;
char s[maxn];
bool is_pal[maxn][maxn];
bool visit_pal[maxn][maxn];
inline int read()
{
	int x=0,f=1;char ch=getchar();
	while (ch<'0'||ch>'9'){if (ch=='-') f=-1;ch=getchar();}
	while (ch>='0'&&ch<='9'){x=x*10+ch-48;ch=getchar();}
	return x*f;
}
void get_is_pal(int l,int r)
{
    if(visit_pal[l][r])
    return;
    if(l==r||r==l+1)
	{
        is_pal[l][r]=(s[l]==s[r]);
        return;
    }
    get_is_pal(l+1,r-1);
    if(is_pal[l+1][r-1])
    is_pal[l][r]=(s[l]==s[r]);
    visit_pal[l][r]=true;
}
int f[maxn][maxn];
bool visit_dp[maxn][maxn];
void get_dp(int l,int r) 
{
    if(visit_dp[l][r])
    return;
    if(l==r)
	{
        f[l][r]=1;
        return;
    }
    if(r==l+1)
	{
        f[l][r]=2+is_pal[l][r];
        return;
	}
    get_dp(l,r-1);
    get_dp(l+1,r);
    get_dp(l+1,r-1);
    f[l][r]=f[l][r-1]+f[l+1][r]-f[l+1][r-1]+is_pal[l][r];
    visit_dp[l][r]=true;
}
int main()
{
	scanf("%s",s+1);
    int len=strlen(s+1);
    for(int x=1;x<=len;x++)
        for(int y=x;y<=len;y++)
            get_is_pal(x,y);
    for(int x=1;x<=len;x++)
        for(int y=x;y<=len;y++)
            get_dp(x,y);
    int T=read();
    while(T--)
    {
    	cout<<f[read()][read()]<<'\n';
	}
    return 0;
}
```

### P1385 密令

##### 思路

首先发现一条性质：我们设字符串的总和为sum，则任何字母总和为sum的等长的串都是可以达到的。

证明：

采用构造方法，我们从前往后构造新的字符串，考虑第一个字符，如果比目标大就用$(-1,+1)$变换，比目标小就用$(+1,-1)$变换，然后去搞第二个字符……一次类推，直到搞完前$n-1$位

至于最后一位，我们断言它此时必定等于目标串的最后一位，这是因为两种变换均不会改变字母和$sum$

于是整个问题就简化为：

给定$sum$，有多少种长度为$n$的序列满足：

1.每个元素在$[1,26]$之间

2.序列和为$sum$

然后就开始DP，设$f[k][x]$表示长度为$k$的序列之和为$x$的方案数量，答案显然是$f[n][sum]$,然后转移就是显然的
$
f[k][x]=\sum_{1 \le i \le min(26,x)}f[k-1][x-i]
$
注意最后要减去原先的那一个

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#define int long long
using namespace std;
const int mod=1e9+7;
int T;
char s[105];
int f[105][5005];
signed main()
{
	cin>>T;
	for(int i=0;i<26;i++)
	f[1][i]=1;
	for(int i=1;i<=100;i++)
	f[i][0]=1;
	for(int k=2;k<=100;k++)
	{
		for(int x=1;x<=2500;x++)
		{
			for(int i=0;i<26;i++)
			{
				if(x-i>=0)
				f[k][x]=(f[k][x]%mod+f[k-1][x-i]%mod)%mod;
			}
		}
	}
	while(T--)
	{
		scanf("%s",s+1);
		int tot=0;
		int len=strlen(s+1);
		for(int i=1;i<=len;i++)
		tot+=(int)(s[i]-'a');
		cout<<f[len][tot]%mod-1<<'\n';//要减去最开始的那一个！！ 
	}
	return 0;
}
```

### CF106C Buns

设$f[k][r]$表示只做前k种包子，使用了r克面团，获得的收益

实际上类似于一个背包

考虑某种包子做$i$个，则有状态转移方程
$
\forall k,r ,f[k][r]=max(f[k][r],f[k-1][r-i*c[k]]+i*d[k])
$

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=1005;
int n,m;
int a[maxn],b[maxn],c[maxn],d[maxn];
int c0,d0;
int f[15][maxn];
int ans;
int main()
{
	cin>>n>>m>>c0>>d0;
	for(int i=1;i<=m;i++)
	cin>>a[i]>>b[i]>>c[i]>>d[i];
	//整挺好，就一个类似于背包的动态规划 
	for(int k=1;k<=m;k++)
    for(int r=0;r<=n;r++)
    for(int i=0;i*b[k]<=a[k]&&i*c[k]<=r;i++)
    f[k][r]=max(f[k][r],f[k-1][r-i*c[k]]+i*d[k]);
    for(int r=0; r<=n; r++)
    ans=max(ans,f[m][r]+(n-r)/c0*d0);
    cout<<ans<<'\n';
    return 0;
}
