# 【全程NOIP计划】初级数据结构2

## 树状数组

可以用于维护前缀信息（可合并）

优点：代码段，速度快

比如：

给定一个长n的数组，支持操作：

1.将第$i$个数$a_i$加$v$

2.询问区间$[l,r]$中的数的和

$lowbit(i)$：只保留$i$的二进制表示中最低位的1

树状数组中，节点$i$表示的区间为$[i-lowbit(i)+1,i]$

##### 前缀查询

查询区间$[1,i]$的和的时候，由$i$可以直接得到$[i-lowbit(i)+1,i]$的和，接下来查询$[1,i-lowbit(i)]$的区间和，重复上面的步骤就可以了

##### 单点修改

修改$i$的时候，寻找包含i的所有区间：

第一个包含$i$且$lowbit$比$i$大的节点是$i+lowbit(i)$

```cpp
int lowbit(int x)
{
    return x&(-x);
}
void add(int x,int y)
{
    for( ;x<=n;x+=lowbit(x)) c[x]+=y;
}
int ask(int x)
{
    int res=0;
    for( ;x;x-=lowbit(x))
        res+=c[x];
    return res;
}
```

##### 差分

实际上就是用树状数组维护一下差分序列的前缀和就行

##### 区间修改

将区间$[l,r]$内的数全加v，或者查询$[l,r]$内数的和

考虑用差分数组来表示$[1,R]$的前缀和
$
\sum_{k=1}^Ra_k=\sum_{k=1}^R \sum_{i=1}^kd_i
\\
=\sum_{i=1}^R \sum_{k=i}^Rd_i
\\
=\sum_{i=1}^R(R-i+1)d_i=(R+1)\sum_{i=1}^Rd_i-\sum_{i=1}^Rid_i
$

### 逆序对

##### 题目

给定序列，求有多少对逆序对

##### 思路

对于每个i，它的前面有多少个数比它大

先离散化，对值域建树状数组

然后从左往右扫描一次，在每个位置需要查询权值的前缀和，然后把这个数加入树状数组

时间复杂度$O(nlogn)$

##### 

##### 二维树状数组

给定n*m的矩阵$a_{i,j}$,有$q$次操作，每次操作修改某个元素或者查询某个子矩阵的和

记录$b_{i,j}$表示从$(i-lowbit(i)+1,j-lowbit(j)+1)$到$(i,j)$的子矩阵的和

查询和修改的时候，先枚举第一维，再枚举第二维

时间复杂度$O(Qlogn \space logm)$

```cpp
void update(int x,int y,int z)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        for(int j=y;j<=m;j+=lowbit(j))
            b[i][j]+=z;
    }
}
int query(int x,int y)
{
    int res=0;
    for(int i=x;i>0;i-=lowbit(i))
    {
        for(int j=y;j>0;j-=lowbit(j))
            res+=b[i][j];
    }
    return res;
}
```

## 线段树

可以用于维护区间信息

比如：

维护长为n的序列：

包括单点修改，区间查询等操作

线段树的形式是一颗二叉树，每个节点维护一段区间的信息

根节点为$[1,n]$

对于节点$[L,R]$，设中点$mid=\lfloor \dfrac {L+R} 2 \rfloor$,把该节点从mid处分开，左边的子节点为$[L,mid]$，右边的子节点为$[mid+1,R]$

树高$O(log n)$，总结点数2n-1

对于节点x。左儿子为2x,右儿子则为2x-1

##### 建树

根节点为$[1,n]$，考虑根节点为$[L,R]$的时候：

设mid=(l+r)/2，对于区间$[L,mid],[mid+1,R]$递归建树

合并两个区间的信息

```cpp
int a[N], mx[N << 2];
void update(int x, int L, int R) {
    if(L != R) {
        mx[x] = max(mx[x << 1], mx[x << 1 | 1]);
    }
}
void build(int x, int L, int R) {
    if(L == R) {
        mx[x] = a[L];
        return;
    }
    int mid = (L + R) >> 1;
    build(x << 1, L, mid);
    build(x << 1 | 1, mid + 1, R);
    update(x, L, R);
}
```

##### 单点修改/查询

单点查询：从上向下找到对应的叶子节点

单点修改：先修改叶子节点，然后从下往上向上更新

```cpp
int query(int x, int L, int R, int p) {
    if(L == R) return mx[x];
    int mid = (L + R) >> 1;
    if(p <= mid) return query(x << 1, L, mid, p);
    else return query(x << 1 | 1, mid + 1, R, p);
}
int modify(int x, int L, int R) {
    if(L == R) {
        mx[x] = v;
        return;
    }
    int mid = (L + R) >> 1;
    if(p <= mid) modify(x << 1, L, mid, p, v);
    else modify(x << 1 | 1, mid + 1, R, p, v);
    update(x, L, R);
}
```

##### 区间查询

查询区间$[l,r]$的时候，可以最多拆成$2log \space n$个不相交区间，合并这些区间可以得到答案

从线段树从上往下找答案

##### 区间修改

对区间$[l,r]$加$v$，同样可以拆成最多$2log\space n$个区间，并修改这些区间

在一个节点做区间修改的时候，不立刻修改它的子节点

记录懒标记：每个节点x记录还没有加到子树中的值的总和

查询经过某节点的时候，将懒标记下放给它的两个儿子

```cpp
int mx[N << 2], sum[N << 2], tag[N << 2];
void update(int x) {
    mx[x] = max(mx[x << 1], mx[x << 1 | 1]);
    sum[x] = sum[x << 1] + sum[x << 1 | 1];
}
void pushdown(int x, int L, int R) {
    if(tag[x] == 0) return;
    sum[x] += tag[x] * (R - L + 1);
    mx[x] += tag[x];
    if(L != R) {
        tag[x << 1] += tag[x];
        tag[x << 1 | 1] += tag[x];
    }
    tag[x] = 0;
}
// a[l...r] += v
void modify(int x, int L, int R, int l, int r, int v) {
    pushdown(x, L, R);
    if(L == l && R == r) {
        tag[x] += v;
        pushdown(x, L, R);
        return;
    }
    int mid = (L + R) >> 1;
    if(r <= mid) modify(x << 1, L, mid, l, r, v);
    else if(l > mid) modify(x << 1 | 1, mid+1, R, l, r, v);
    else{
        modify(x << 1, L, mid, l, mid, v);
        modify(x << 1 | 1, mid+1, R, mid+1, r, v);
    }
    update(x);
}
```

##### 标记永久化

```cpp
// -------------- 标记永久化 ---
void modify(int x, int L, int R, int l, int r, int v) {
    if(L == l && R == r) {
        tag[x] += v;
        sum[x] += tag[x] * (R - L + 1);
        mx[x] += tag[x];
        return;
    }
    int mid = (L + R) >> 1;
    if(r <= mid) modify(x << 1, L, mid, l, r, v);
    else if(l > mid) modify(x << 1 | 1, mid+1, R, l, r, v);
    else{
        modify(x << 1, L, mid, l, mid, v);
        modify(x << 1 | 1, mid+1, R, mid+1, r, v);
    }
    update(x, L, R);
}
int query(int x, int L, int R, int l, int r, int cur) {
    if(l == L && r == R)
        // return mx[x] + cur;
        return sum[x] + cur * (r - l + 1);
    cur += tag[x];
    int mid = (L + R) >> 1;
    if(r <= mid) return query(x << 1, L, mid, l, r, cur);
    else if(l > mid) return query(x << 1 | 1, mid + 1, R, l, r, cur);
    else{
        int u = query(x << 1, L, mid, l, mid, cur);
        int v = query(x << 1 | 1, mid + 1, R, mid + 1, r, cur);
        // return max(u, v);
        return u + v;
    }
}
```

### P2023 维护序列

##### 思路

实际上就是多一个乘法标记，跟线段树2差不多，就一板子

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=100010;
int p;
int a[maxn+5];
struct tree{
	int l,r;
	long long dat,lazy,mul;
}t[maxn*4+5];
void pushup(int k)
{
	t[k].dat=(t[k<<1].dat+t[k<<1|1].dat)%p;
}
void build(int k,int l,int r)
{
	t[k].lazy=0,t[k].mul=1;
	t[k].l=l,t[k].r=r;
	if(l==r)
	{
		t[k].dat=a[l];
		return ;
	}
	int mid=(l+r)>>1;
	build(k<<1,l,mid);
	build(k<<1|1,mid+1,r);
	pushup(k);
}
void pushdown(int k)
{
		t[k<<1].dat=(t[k<<1].dat*t[k].mul+t[k].lazy*(t[k<<1].r-t[k<<1].l+1))%p;
		t[k<<1|1].dat=(t[k<<1|1].dat*t[k].mul+t[k].lazy*(t[k<<1|1].r-t[k<<1|1].l+1))%p;
		t[k<<1].mul=(t[k<<1].mul*t[k].mul)%p;
		t[k<<1|1].mul=(t[k<<1|1].mul*t[k].mul)%p;
		t[k<<1].lazy=(t[k<<1].lazy*t[k].mul+t[k].lazy)%p;
		t[k<<1|1].lazy=(t[k<<1|1].lazy*t[k].mul+t[k].lazy)%p;
		t[k].mul=1;
		t[k].lazy=0;
}
void updata(int k,int l,int r,int v)
{
	if(l<=t[k].l&&r>=t[k].r)
	{
		t[k].dat=(t[k].dat+(long long)v*(t[k].r-t[k].l+1))%p;
		t[k].lazy=(t[k].lazy+v)%p;
		return ;
	}
	pushdown(k);
	int mid=(t[k].l+t[k].r)>>1;
	if(l<=mid)
	updata(k<<1,l,r,v);
	if(r>mid)
	updata(k<<1|1,l,r,v);
	pushup(k);
}
void updata2(int k,int l,int r,int v)
{
	if(l<=t[k].l&&r>=t[k].r)
	{
		t[k].dat=(t[k].dat*v)%p;
		t[k].lazy=(t[k].lazy*v)%p;
		t[k].mul=(t[k].mul*v)%p;
		return ;
	}
	pushdown(k);
	int mid=(t[k].l+t[k].r)>>1;
	if(l<=mid)
	updata2(k<<1,l,r,v);
	if(r>mid)
	updata2(k<<1|1,l,r,v);
	pushup(k);
}
long long query(int k,int l,int r)
{
	if(l<=t[k].l&&r>=t[k].r)
	return t[k].dat;
	pushdown(k);
	int mid=(t[k].l+t[k].r)>>1;
	long long ans=0%p;
	if(l<=mid)
	ans+=query(k<<1,l,r)%p;
	if(r>mid)
	ans+=query(k<<1|1,l,r)%p;
	return ans%p;
}
int main()
{
	std::ios::sync_with_stdio(false);
	int n,m;
	cin>>n>>p;
	for(int i=1;i<=n;i++)
	cin>>a[i];
	cin>>m;
	build(1,1,n);
	for(int i=1;i<=m;i++)
	{
		int o;
		cin>>o;
		if(o==1)
		{
			int x,y,k;
			cin>>x>>y>>k;
			updata2(1,x,y,k);
			continue;
		}
		if(o==2)
		{
			int x,y,k;
			cin>>x>>y>>k;
			updata(1,x,y,k);
			continue;
		}
		if(o==3)
		{
			int x,y;
			cin>>x>>y;
			cout<<query(1,x,y)<<'\n';
		}
	}
	return 0;
}
```

### P4513 小白逛公园

##### 思路

在每个节点处维护：

区间最大字段和，区间最大前缀和和区间最大后缀和

合并的时候分类讨论就好了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=500005;
int n,m;
int a[maxn];
struct tree{
	int l,r;
	int sum,lmax,rmax,maxx;
}t[maxn*4];
void pushup(int k)
{
	t[k].sum=t[k<<1].sum+t[k<<1|1].sum;
	t[k].lmax=max(t[k<<1].sum+t[k<<1|1].lmax,t[k<<1].lmax);
	t[k].rmax=max(t[k<<1|1].sum+t[k<<1].rmax,t[k<<1|1].rmax);
	t[k].maxx=max(max(t[k<<1].maxx,t[k<<1|1].maxx),t[k<<1].rmax+t[k<<1|1].lmax);
}
void build(int k,int l,int r)
{
	t[k].l=l,t[k].r=r;
	if(l==r)
	{
		t[k].sum=t[k].lmax=t[k].rmax=t[k].maxx=a[l];
		return ;
	}
	int mid=(l+r)>>1;
	build(k<<1,l,mid);
	build(k<<1|1,mid+1,r);
	pushup(k);
}
void update(int k,int p,int v)
{
	if(t[k].l==t[k].r)
	{
		t[k].sum=t[k].lmax=t[k].rmax=t[k].maxx=v;
		return ;
	}
	int mid=(t[k].l+t[k].r)>>1;
	if(mid>=p)
	update(k<<1,p,v);
	else
	update(k<<1|1,p,v);
	pushup(k);
}
tree query(int k,int l,int r)
{
	if(l<=t[k].l&&t[k].r<=r)
	return t[k];
	int mid=(t[k].l+t[k].r)>>1;
	if(r<=mid)
	return query(k<<1,l,r);
	else if(l>mid)
	return query(k<<1|1,l,r);
	else
	{
		tree x=query(k<<1,l,r);
		tree y=query(k<<1|1,l,r);
		tree merge;
		merge.sum=x.sum+y.sum;
		merge.lmax=max(x.sum+y.lmax,x.lmax);
		merge.rmax=max(y.sum+x.rmax,y.rmax);
		merge.maxx=max(max(x.maxx,y.maxx),x.rmax+y.lmax);
		return merge;
	}
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	cin>>a[i];
	build(1,1,n);
	for(int i=1;i<=m;i++)
	{
		int op;
		cin>>op;
		if(op==1)
		{
			int a,b;
			cin>>a>>b;
			if(a>b) swap(a,b);
			tree ans=query(1,a,b);
			cout<<ans.maxx<<'\n';
		}
		else
		{
			int p,s;
			cin>>p>>s;
			update(1,p,s); 
		}
	}
	return 0;
}
```

### P2894 Hotel

##### 思路

线段树

类似上一道题目

在每个节点处维护：

区间内最长全0的长度，最长全0前缀和最长全0后缀

查询时，在线段树上二分找到最靠前的答案

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=500005;
int n,m;
struct tree{
	int sum;
	int len;
	int lmax,rmax;
	int lazy;
}t[maxn*4];
void pushup(int k)
{
	if(t[k<<1].sum==t[k<<1].len)
	t[k].lmax=t[k<<1].len+t[k<<1|1].lmax;
	else 
	t[k].lmax=t[k<<1].lmax;

	if(t[k<<1|1].sum==t[k<<1|1].len)
	t[k].rmax=t[k<<1|1].len+t[k<<1].rmax; 
	else 
	t[k].rmax=t[k<<1|1].rmax;

	t[k].sum=max(max(t[k<<1].sum,t[k<<1|1].sum),t[k<<1].rmax+t[k<<1|1].lmax);
} 
void pushdown(int k)
{
	if(t[k].lazy==0)
	return;
	if(t[k].lazy==1)
	{
	    t[k<<1].lazy=t[k<<1|1].lazy=1;
		t[k<<1].sum=t[k<<1].lmax=t[k<<1].rmax=0;
		t[k<<1|1].sum=t[k<<1|1].lmax=t[k<<1|1].rmax=0;
	}
	if(t[k].lazy==2)
	{
		t[k<<1].lazy=t[k<<1|1].lazy=2;
		t[k<<1].sum=t[k<<1].lmax=t[k<<1].rmax=t[k<<1].len;
		t[k<<1|1].sum=t[k<<1|1].lmax=t[k<<1|1].rmax=t[k<<1|1].len;
	}
	t[k].lazy=0;
}
void build(int k,int l,int r)
{
	t[k].lazy=0;
	t[k].sum=t[k].len=t[k].lmax=t[k].rmax=r-l+1;
	if(l==r)
	return;
	int mid=(l+r)/2;
	build(k<<1,l,mid);
	build(k<<1|1,mid+1,r); 
}
void update(int k,int l,int r,int tag,int L,int R)
{
	pushdown(k);
	if(L<=l&&r<=R)
	{
    	if(tag==1)t[k].sum=t[k].lmax=t[k].rmax=0;
		else t[k].sum=t[k].lmax=t[k].rmax=t[k].len; 
		t[k].lazy=tag;
		return;
	}
	int mid=(l+r)/2;
	if(L<=mid)
	update(k<<1,l,mid,tag,L,R);
	if(R>mid)
	update(k<<1|1,mid+1,r,tag,L,R);
	pushup(k);
}
int query(int k,int l,int r,int length)
{
	pushdown(k);
	if(l==r)return l;
	int mid=(l+r)/2;
	if(t[k<<1].sum>=length)
	return query(k<<1,l,mid,length);
	if(t[k<<1].rmax+t[k<<1|1].lmax>=length)
	return mid-t[k<<1].rmax+1;
	else 
	return query(k<<1|1,mid+1,r,length);
}
int main()
{
	cin>>n>>m;
	build(1,1,n);
	for(int i=1;i<=m;i++) 
	{
		int op,x,y;
		cin>>op;
		if(op==1)
		{
			cin>>x;
			if(t[1].sum>=x)
			{
				int l=query(1,1,n,x);
				cout<<l<<'\n';
				update(1,1,n,1,l,l+x-1);
			}
			else
			cout<<0<<'\n';
		}
		else
		{
			cin>>x>>y;
			update(1,1,n,2,x,x+y-1);
		}
	}
	return 0;
}
```

