维护被覆盖的面基，节点记录：

实际区间长度，被覆盖部分长度，最小值，最小值部分长度

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <string>
#include <cstring>
using namespace std;
const int maxn=1e6+5;
int n;
long long x1,y1,x2,y2;
long long x[maxn*2];
struct scanline{
	long long l,r,h;
	int mark;
	bool operator < (const scanline &rhs) const
	{
		return h<rhs.h;
	}
}line[maxn*2];
struct tree{
	int l,r;
	int sum;
	long long len;
}t[maxn*4];
void pushup(int k)
{
	if(t[k].sum)
	t[k].len=x[t[k].r+1]-x[t[k].l];
	else
	t[k].len=t[k<<1].len+t[k<<1|1].len;
}
void build(int k,int l,int r)
{
	t[k].l=l,t[k].r=r;
	t[k].len=0;
	t[k].sum=0;
	if(l==r)
	return ;
	int mid=(l+r)>>1;
	build(k<<1,l,mid);
	build(k<<1|1,mid+1,r);
}
void edit_tree(int k,long long l,long long r,int c)
{
	if(x[t[k].r+1]<=l||r<=x[t[k].l])
	return ;
	if(l<=x[t[k].l]&&x[t[k].r+1]<=r)
	{
		t[k].sum+=c;
		pushup(k);
		return ;
	}
	edit_tree(k<<1,l,r,c);
	edit_tree(k<<1|1,l,r,c);
	pushup(k);
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>x1>>y1>>x2>>y2;
		x[2*i-1]=x1,x[2*i]=x2;
		line[2*i-1]=(scanline){x1,x2,y1,1};
		line[2*i]=(scanline){x1,x2,y2,-1};
	}
	n<<=1;
	sort(line+1,line+1+n);
	sort(x+1,x+1+n);
	//离散化 
	int tot=unique(x+1,x+1+n)-x-1;
	build(1,1,tot-1);
	long long ans=0;
	for(int i=1;i<n;i++)
	{
		edit_tree(1,line[i].l,line[i].r,line[i].mark);

		ans+=t[1].len*(line[i+1].h-line[i].h);
	}
	cout<<ans<<endl;
	return 0;
}
