```cpp
#include<iostream>
#include<cstdio>
#include<cmath>
#include<queue>
#include<cstring>
using namespace std;
const int maxn = 1005;
const double eps=1e-4;
int n,m;
int x[maxn],y[maxn];
int vis[maxn];
double dis[maxn][maxn];
queue<int> q;
int check(double mid)
{
    memset(vis,0,sizeof(vis));
    vis[0]=1;
    q.push(0);
    while(!q.empty())
    {
        int v=q.front();q.pop();
        for(int i=1;i<=m+1;i++)
        {
            if(!vis[i])
            {
                if(i==m+1||v==0)
				{
					if(dis[v][i]<=mid)
					vis[i]=1,q.push(i);
				}
                else if(dis[v][i]<=2*mid)
				vis[i]=1,q.push(i);
            }
        }
    }
    return vis[m+1];
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
        dis[0][i]=dis[i][0]=x[i];
        dis[m+1][i]=dis[i][m+1]=n-x[i];
    }
    dis[0][m+1]=(1<<30);
    for(int i=1;i<=m;i++)
        for(int j=i+1;j<=m;j++)
            dis[i][j]=dis[j][i]=sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
    double l=0,r=10005,ans,mid;
    while(r-l>=eps)
    {
        mid=(l+r)/2;
        if(check(mid)) r=mid,ans=mid;
        else l=mid;
    }
    printf("%.2lf",ans);
    return 0;
}
