int n,m;
int a[100005];
int lg[100005]={-1};
int f[100005][50];
int main()
{
    std::ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		lg[i]=lg[i/2]+1;
	}
	for(int i=1;i<=n;i++)
	f[i][0]=a[i];
	for(int i=1;i<=lg[n];i++)
	{
		for(int j=1;j+(1<<i)-1<=n;j++)
		f[j][i]=max(f[j][i-1],f[j+(1<<(i-1))][i-1]);
	}
	while(m--)
	{
		int l,r;
		cin>>l>>r;
		int len=lg[r-l+1];
		cout<<max(f[l][len],f[r-(1<<len)+1][len])<<endl;
	}
	return 0;
}
