{
	edge[++en].e=y;
	edge[en].next=first[x];
	first[x]=en;
}
int f[maxn][21],g[maxn][21],dep[maxn];
inline void dfs(int u,int fa) 
{
	dep[u]=dep[fa]+1;
	f[u][0]=fa; g[u][0]=c[fa];
	for(int i=1;(1<<i)<=dep[u];i++) f[u][i]=f[f[u][i-1]][i-1],g[u][i]=g[f[u][i-1]][i-1]+g[u][i-1];
	for(int i=first[u];i;i=edge[i].next) 
	{
		int v=edge[i].e;
		dfs(v,u);
	}
}
