		while (s.size()&&d[i]>d[s.top()]) 
		{
			l[s.top()]=i;
			s.pop();
		}
		s.push(i);
	}
	for(int i=1;i<=n;i++) add(l[i],i);
	dfs(n+1,0);
	for(int i=1;i<=q;i++) 
