		for(int i=20;i>=0;i--) {
			if (g[x][i]<=v&&(1<<i)<=dep[x]) 
			{
				v-=g[x][i]; x=f[x][i];
			}
			if (v==0) ans=x;
		}
		if (ans==0) 
		ans=f[x][0];
		if (ans==n+1) 
