	first[s]=en;
	ed[en].e=e;
}
bool check(int l,int r)
{
	int cnt=0;
	for(int i=l;i<=r;i++)
	{
		if(s[i]=='(') cnt++;
		else if(s[i]==')') cnt--;
		if(cnt<0) return false;
	}
	if(cnt==0) return true;
	return false;
}
signed main()
{
