		add_edge(i+1,x);
		add_edge(x,i+1);
	}
	if(flag)
	{
		for(int i=1;i<=n;i++)
		{
			if(s[i]==')')
			{
				if(size==0) continue;
				int t=st[size];
				don[i]=don[t-1]+1;
