- 菊花图

菊花图的话有一个花心和一堆花瓣

然后我们根据手模可以发现

可以按照结点的编号和数字进行贪心

当我们处理一个点的时候，对于一个数字，枚举跟它相连的点

如果这个相邻的点没有被访问过，并且这个点是最后一个数字或者和之前这个数字并没有产生过直接联系

我们就以这个数字为排列的下一个数字

可以得到25pts

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <cmath>
using namespace std;
const int maxn=4005;
int p[maxn],ans[maxn];
bool vis[maxn];
int fa[maxn];
int get(int x)
{
    return fa[x]=(x==fa[x]? x:get(fa[x]));
}
int main()
{
    int n,T;
    cin>>T;
    while(T--)
    {
    	memset(vis,false,sizeof(vis));
    	cin>>n;
		for(int i=1;i<=n;i++)
		    fa[i]=i;
		for(int i=1;i<=n;i++)
		    cin>>p[i];
		int x,y;
		for(int i=1;i<n;i++)
	    cin>>x>>y;
		for(int i=1;i<=n;i++)
		{
		    int x=p[i];
		    for(int j=1;j<=n;j++)
		    {
				if(!vis[j]&&(i==n||get(x)!=get(j)))
				{
				    ans[i]=j;
				    fa[get(x)]=get(j);
				    vis[j]=true;
				    break;
				}
	   		}
		}	
		for(int i=1;i<=n;i++)
	    	cout<<ans[i]<<" ";
		cout<<'\n';
    }
    return 0;
}
```

我们发现可以用拓扑序的模型来贪心

怎么贪呢

我们为每条边规定一个优先级，如果一条边的优先级大于另一条边的话，那么这条边必须造另一条边的后面删除

所以我们按照这个思路贪心，每次选一个当前数字能到达的，不和之前的条件冲突的，标号最小的结点作为这个数字最终所在的结点，然后将这个条件加入

这个怎么做呢，我们可以用一堆方法标记一下一条边和左右两条边的优先级，然后每次从当前数字开始找左右两边符合条件的点，然后把新条件对应的标记值更新就好了

然后我们继续考虑正解

我们按照上面的思路继续思考

我们发现，只有与同一个节点相邻的边之间才会有优先级的问题存在

我们对每一个点，开一个并查集，然后对每一个并查集建一个虚点

如果一条边的优先级最大，那么直接用虚点向他连一条边

如果一条边优先级最小，那么它向虚点连一条边然后套第一个25pts的代码，然后再结合上面的贪心思路，每次从一个点出发遍历整棵树，每走一条边就判断一次，然后对一条路径进行修改就好了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=20005;
struct edge{
	int e,next;
}ed[maxn];
int en,first[maxn];
void add_edge(int s,int e)
{
	en++;
	ed[en].next=first[s];
	first[s]=en;
	ed[en].e=e;
}

int fa[maxn],size[maxn],d[maxn],p[maxn],ans;

bool in[maxn],out[maxn];

int get(int x)
{
    return fa[x]=(x==fa[x]? x:get(fa[x]));
}
void merge(int x,int y)
{
    int u=get(x),v=get(y);
    fa[u]=v,size[v]+=size[u];
    out[x]=in[y]=true;
}
bool check(int x,int y,int l)
{
    if(in[y]||out[x])
	return false;
    int u=get(x),v=get(y);
    if(u==v&&size[u]!=l)
	return false;
    return true;
}
void dfs1(int v,int fath)
{
    if(fath!=v&&check(fath,v,d[v]+1))
	ans=min(ans,v);
    for(int i=first[v];i;i=ed[i].next)
    {
		int u=ed[i].e;
		if(i==fath) continue;
		if(check(fath,i,d[v]+1))
	    	dfs1(u,i^1);
    }
}
bool dfs2(int v,int fath,int p)
{
    if(v==p)
    {
		merge(fath,v);
		return true;
    }
    for(int i=first[v];i;i=ed[i].next)
    {
		int u=ed[i].e;
		if(i==fath) continue;
		if(dfs2(u,i^1,p))
		{
		    merge(fath,i);
		    return true;
		}
    }
    return false;
}
int main()
{
    int T,n;
    cin>>T;
    while(T--)
    {
		cin>>n;
		memset(first,0,sizeof(first));
		memset(in,0,sizeof(in));
		memset(out,0,sizeof(out));
		memset(ed,0,sizeof(ed));
		memset(d,0,sizeof(d));
		en=(n+1)/2*2+1;
		for(int i=1;i<=n;i++)
	    cin>>p[i];
		for(int i=1;i<n;i++)
		{
		    int x,y;
		    cin>>x>>y;
		    d[x]++,d[y]++;
		    add_edge(x,y);
		    add_edge(y,x);
		}
		for(int i=1;i<=en;i++)
		    fa[i]=i,size[i]=1;
		for(int i=1;i<=n;i++)
		{
		    int v=p[i];
		    ans=n+1;
		    dfs1(v,v);
		    dfs2(v,v,ans);
		    cout<<ans<<" ";
		}
		cout<<'\n';
    }
    return 0;
}
```

## Day2

### T1 Emiya家今天的饭

#### 思路

动态规划

我们先不考虑每列不超过一半的限制，求出总的方案数量，然后再减去考虑这个限制之后不合法的方案数目

所以我们问题现在就变成了求任意列所选的结点超过所有选的结点的一般的方案数目

肯定只有一列的超过总结点的一半，所以我们枚举这个超过的列，然后DP

设 $f[i][j][k]$ 表示前 $i$ 行选 $j$ 个结点，当前列选了 $k$ 个结点的方案数量

然后发现，我们实际上只是想知道 $j,k$ 的大小关系，所以我们把 $j,k$ 合并到一维

我们就要限制 $k > \lfloor\dfrac j 2 \rfloor$ ,然后 $2k+n-j>n$ 

我们观察发现 $n-j$ 就是 没有选的行

对于每个结点，如果选了，那么这个行就选了两次

如果这个行没有选的话，所有列选了一次

所以我们要找的就是当前列被选超过 $n$ 次的方案

所以就有 
$
f[j][k]=(f[j][k]+f[j-1][k]*(cnt[j]-w[j][i]))
\\
f[j][k+1]=(f[j][k+1]+f[j-1][k])
\\
f[j][k+2]=(f[j][k+2]+f[j-1][k]*w[j][i])
$
在计算的时候都模一个 $998244353$ 就好了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#define int long long
using namespace std;
const int maxn=205;
const int maxm=3005;
const int mod=998244353;
int n,m;
int ans=1;
int cnt[maxn],a[maxn][maxm],f[maxn][maxm];
signed main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cin>>a[i][j];
			cnt[i]=(cnt[i]+a[i][j])%mod;
		}
		ans=(ans*(cnt[i]+1))%mod;
	}
	ans=(ans+mod-1)%mod;
	for(int i=1;i<=m;i++)
	{
		memset(f,0,sizeof(f));
		f[0][0]=1;
		for(int j=1;j<=n;j++)
		{
			for(int k=0;k<=2*(j-1);k++)
			{
				f[j][k]=(f[j][k]+f[j-1][k]*(cnt[j]-a[j][i]))%mod;
				f[j][k+1]=(f[j][k+1]+f[j-1][k])%mod;
				f[j][k+2]=(f[j][k+2]+f[j-1][k]*a[j][i])%mod;
			}
		}
		for(int j=n+1;j<=2*n;j++)
		ans=(ans+mod-f[n][j])%mod;
	}
	cout<<ans<<'\n';
	return 0;
}
```

### T2 划分

#### 思路

简化一下题意

就是对于一个长度为 $n$ 的序列 $\{a_i\}$ ，我们将这个序列划分成若干个部分，使得这个序列的每个部分的和从左向右递增，且它们和的平方的和最小

我们观察可以发现，分成的序列越多越好，最后一个越小越好

因为 
$
(x+y)^2 \ge x^2+y^2
$
所以我们考虑动态规划

我们设 $f[i][j]$ 表示划分到第 $i$ 个段，前驱为 $j$ 的最小时间

则有
$
f[i][j]=f[j][k]+(sum[i]-sum[j])^2
$
其中 $sum[i]$ 可以前缀和预处理一下

然后我们考虑优化一下，如果 $j$ 固定不动的话，我们可以发现在移动 $i$ 的过程中 $k$ 也在移动，满足一个单调的性质，我们对 $f[j][k]$ 维护一个最小值的单调序列

然后接着，我们可以发现一个结论

$f[i][j] \le f[i][j-1]$ 在合法的时候是恒成立的

所以我们最右边的前驱是最优的，所以我们不考虑更新，我们考虑转移的点

维护一个单调序列，最左边的前驱，因为前缀和也是单调的，所以当左边队首加一的时候移动左端点，右端点维护单调递增的区间段，如果有了赚一点之后，我们就能直接算答案了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=40000005;
const int maxm=100005;
const int mod=(1<<30);
int n,type;
int x,y,z,m;
int a[maxn],b[maxn];
int l[maxm],r[maxm],p[maxm];
int q[maxn],pre[maxn];
long long sum[maxn];
inline long long d(int x)
{
	return sum[x]-sum[pre[x]];
}
signed main()
{
	cin>>n>>type;
	if(type==1)
	{
		cin>>x>>y>>z;
		cin>>b[1]>>b[2]>>m;
		for(int i=1;i<=m;i++)
		cin>>p[i]>>l[i]>>r[i];
		for(int i=3;i<=n;i++)
		b[i]=(1ll*b[i-1]*x+1ll*b[i-2]*y+z)%mod;
		for(int i=1;i<=m;i++)
		{
			for(int j=p[i-1]+1;j<=p[i];j++)
			{
				a[j]=(b[j]%(r[i]-l[i]+1))+l[i];
				sum[j]=sum[j-1]+a[j];
			}
		}
	}
	else
	{
		for(int i=1;i<=n;i++)
		{
			cin>>a[i];
			sum[i]=sum[i-1]+a[i];
		}
	}
	int head=0,tail=0;
	q[0]=0;
	for(int i=1;i<=n;i++)
	{
		while(head<tail&&d(q[head+1])+sum[q[head+1]]<=sum[i])
		head++;
		pre[i]=q[head];
		while(head<tail&&d(q[tail])+sum[q[tail]]>=d(i)+sum[i])
		tail--;
		q[++tail]=i;
	}
	int now=n;
	__int128 ans=0,tmp=1;
	while(now)
	{
		tmp=d(now);
		tmp*=d(now);
		ans+=tmp;
		now=pre[now];
	}
	int st[50];
	int tp=0;
	while(ans)
	{
		st[++tp]=ans%10;
		ans/=10;
	}
	while(tp)
	cout<<st[tp--];
	return 0;
}
```



### T3 树的重心

#### 思路

巨难的题目

就来赏析一下吧

**摘自@xht**

考虑每个点作为重心的次数

首先拿出一个重心当做根 $root$

对于一个不是 $root$ 的点 $x$ ，如果 $x$ 是鸽掉的某跳边的重心，这条边一定不在 $x$ 的子树之内

设鸽掉一条边之后 ，另外一棵树的大小为 $S$

设 $g_x=max_{g\in son(x)}\{s_y\}$ 也就是 $x$ 的子树内最大的一个子树

因为 $x$ 是重心，所以根据定义，这个点的最大子树不超过这个子树大小的一半，有：
$
2 \times (n-S-s_x) \le n-S
\\
2 \times g_x \le n-S
$
即
$
n-2s_x \le S \le n-2g_x
$
所以我们要找到一个 $x$ ，问有多少条割掉的边满足：

1. $n-2s_x \le S \le n-2g_x$
2. 边不在 $x$ 的子树内

如果只有第一个条件，可以进行一次 $dfs$ ，同时拿一个树状数组动态维护割掉当前点和其父亲之间的边之后的每一个 $S$ 的值有多少个，那么对于每一个点的询问实际上就是一区间求和

然后我们要去掉不满足第二个条件，即在 $x$ 的子树内的边，可以再拿一个树状数组按照 $dfs$ 序动态维护经过所有的点的每一个 $s$ 值有几个，然后我们对于每一个点，在其子树内可以割掉的边就是回溯与进入时区间求和的差

当 $x=root$ 时怎么办呢？

我们可以设 $x$ 的儿子中最大的结点为 $u$ ,第二大的结点为 $v$ 

如果割掉的边在 $u$ 的子树中，则要满足：
$
2 \times s_v \le n-S
$
移项
$
S \le n-2s_v
$
如果不在，则有 ：
$
2 \times s_u \le n-S
$
即 $S \le n-2s_u$

都可以在 $dfs$ 的时候直接维护

这道题主要是关于树状数组的用法问题吧

```cpp
#include <iostream>#include <cstdio>#include <algorithm>#include <cstring>#include <string>#include <vector>#define int long longusing namespace std;const int maxn=3e5+5;struct edge{	int e,next;}ed[maxn<<1];int en,first[maxn];void add_edge(int s,int e){	en++;	ed[en].next=first[s];	first[s]=en;	ed[en].e=e;}int n,root,s[maxn],g[maxn];int u,v,z[maxn];int ans,c1[maxn],c2[maxn];inline int lowbit(int x){	return x&(-x);}inline void add(int *c,int x,int k) {	x++;	for( ;x<=n+1;x+=lowbit(x))	c[x]+=k;}inline int ask(int *c,int x) {	x++;	int res=0;	for( ;x;x-=lowbit(x))	res+=c[x];	return res;}void dfs1(int x, int fa) {	s[x]=1,g[x]=0;	bool flag=true;	for(int i=first[x];i;i=ed[i].next) 	{		int y=ed[i].e;		if(y==fa) continue;		dfs1(y,x);		s[x]+=s[y];		g[x]=max(g[x],s[y]);			if(s[y]>(n>>1)) 		flag=0;	}	if(n-s[x]>(n>>1)) 	flag=false;	if(flag) 	root=x;}void dfs2(int x,int fa) {	add(c1,s[fa],-1);	add(c1,n-s[x],1);	if (x^root) 	{		ans+=x*ask(c1,n-2*g[x]);		ans-=x*ask(c1,n-2*s[x]-1);		ans+=x*ask(c2,n-2*g[x]);		ans-=x*ask(c2,n-2*s[x]-1);		if(!z[x]&&z[fa]) 		z[x]=1;		ans+=root*(s[x]<=n-2*s[z[x]?v:u]);	}	add(c2,s[x],1);	for(int i=first[x];i;i=ed[i].next) 	{		int y=ed[i].e;		if(y==fa)		continue;		dfs2(y,x);	}	add(c1,s[fa],1);	add(c1,n-s[x],-1);	if(x^root) 	{		ans-=x*ask(c2,n-2*g[x]);		ans+=x*ask(c2,n-2*s[x]-1);	}}inline void init() {	memset(ed,0,sizeof(ed));	memset(first,0,sizeof(first));	en=0;	u=v=0;	ans=0;	memset(c1,0,sizeof(c1));	memset(c2,0,sizeof(c2)); }signed main(){	int T;	cin>>T;	while(T--) 	{		init();		cin>>n;		for(int i=1;i<=n-1;i++) 		{			int x,y;			cin>>x>>y;			add_edge(x,y);			add_edge(y,x);		}		dfs1(1,0);		dfs1(root,0);		for(int i=first[root];i;i=ed[i].next) 		{			int x=ed[i].e;			if(s[x]>s[v]) 			v=x;			if(s[v]>s[u])			swap(u,v);		}		for(int i=0;i<=n;i++) 		{			add(c1,s[i],1);			z[i]=0;		}		z[u]=1;		dfs2(root,0);		cout<<ans<<'\n';	}	return 0;}
```

