	for(int i=1;i<=n;i++)
	C[i]=s1[i]*s2[i]%MOD,s3[i]=(s3[i-1]+C[i]%MOD);
	for(int i=1;i<=n;i++)
	{
		A[i]=(A[i-1]+s1[i])%MOD;
		B[i]=(B[i-1]+s2[i])%MOD;
	}
	long long ans=0;
	long long res=1;
	for(int i=1;i<=n;i++)
	ans=((ans+s3[n]-s3[i-1]+C[i-1]*(n-i+1)%MOD-s2[i-1]*(A[n]-A[i-1])%MOD-s1[i-1]*(B[n]-B[i-1])%MOD+MOD)%MOD+MOD)%MOD;
	cout<<ans<<'\n';
