### T5 多叉树

#### 思路

我们如果离线的话

我们可以将一整棵树的形态弄出来，然后再直接处理

设 $f[i]$ 表示以 $i$ 为根的子树插入数字可以有多少种方案

显然，$i$ 节点自身只能填 $0$

所以对于它的一棵子树  $j$ ，我们只能用剩下的 $size[i]-1$ 个数字中的 $size[j]$ 个填入这个子树

所以对答案的贡献是 $f[j] \times C_{size[i]-1}^{size[j]}$

所以状态转移方程是 
$
f[i]= \prod_{j \in son(i)} (f[j] \times C_{size[i]-1}^{size[j]})
$
如果是强制在线的话，我们在连边的时候吧贡献直接乘到 $f[i]$ 里面就好了

然后用并查集处理，预处理阶乘求组合数，快速幂求逆元即可

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <queue>
#define int long long
using namespace std;
const int mod=1000000007;
const int maxn=300005;
int n,m,ans;
int fa[maxn];
int fac[maxn],f[maxn],size[maxn];
int get(int x)
{
	return fa[x]=(x==fa[x]? x:get(fa[x]));
}
int ksm(int a,int b)
{
	int res=1;
	while(b)
	{
		if(b&1)
		res=1ll*res%mod*a%mod;
		a=1ll*a%mod*a%mod;
		b>>=1;
	}
	return res%mod;
}
void init()
{
	for(int i=1;i<=n;i++)
	{
		f[i]=size[i]=1;
		fa[i]=i;
	}
	fac[0]=fac[1]=1;
	for(int i=2;i<=n;i++)
	fac[i]=(fac[i-1]*i)%mod;
}
int C(int x,int y)
{
	return fac[x]*ksm(fac[y],mod-2)%mod*ksm(fac[x-y],mod-2)%mod;
}
void merge(int x,int y)
{
	int f1=get(x),f2=get(y);
	f[f2]=(f[f2]*C(size[f1]+size[f2]-1,size[f1])%mod*f[f1])%mod; 
	fa[f1]=f2,size[f2]+=size[f1];
}
signed main()
{
	cin>>n>>m;
	init();
	while(m--)
	{
		int op;
		cin>>op;
		if(op==1)
		{
			int x,y;
			cin>>x>>y;
			x=(x+ans)%n+1;
			y=(y+ans)%n+1;
			merge(x,y);
		}
		else
		{
			int x;
			cin>>x;
			x=(x+ans)%n+1;
			ans=f[get(x)];
			cout<<ans<<'\n';
		}
	}
	return 0;
}
```

