### T3 赛道修建

#### 思路

思路沿用自 @first_fan

简要题意就是

给定一棵树的信息，求这棵树 $m$ 条互不相交的链中的最小值的最大值可以是多少

求**最小值最大**，显然的**二分**

我们可以知道，如果一条链，经过了一个结点 $i$ 的父节点，同时包含了 $i$ 到子节点的某条边，那么它就只能包含 $i$ 到所有子节点中边的一条

于是我们推出来，对于任意结点 $i$ 和它的子节点 $j,k$ 以及其中的一条链 $i \rightarrow j$ ，我们有三种情况需要讨论

- 不要
- 我们用 $j \rightarrow i \rightarrow k$ 的链
- 我们用 $f_i \rightarrow i \rightarrow j$  的链

所以，我们对于 $i$ 尝试连边，然后如果连一个的话，我们就把新的边长向上传递，和父节点并成同一个链

我们是在二分最小值，所以按照上面的步骤连边之后，如果链长大于 $len$ 的话，我们就重新开一个新的链，如果链数不够的话，说明我们最小的还要更小

我们每次传回的父节点一定要足够长

所以有 $len_{pre}+len_{now} \ge binary_{len}$

然后用 $multiset$ 维护一下就好了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <set>
#define int long long
using namespace std;
const int maxn=50005;
struct edge{
	int e,next,val;
}ed[maxn<<1];
int en,first[maxn];
void add_edge(int s,int e,int val)
{
	en++;
	ed[en].next=first[s];
	first[s]=en;
	ed[en].e=e;
	ed[en].val=val;
}
int n,m,mid,ans;
int f[maxn],g[maxn];
multiset <int> s;
multiset <int>::iterator it;
inline int read()
{
	int x=0,f=1;char ch=getchar();
	while (ch<'0'||ch>'9'){if (ch=='-') f=-1;ch=getchar();}
	while (ch>='0'&&ch<='9'){x=x*10+ch-48;ch=getchar();}
	return x*f;
}
void init()
{
	memset(f,0,sizeof(f));
	memset(g,0,sizeof(g));
}
void dfs(int x,int fa)
{
	for(int i=first[x];i;i=ed[i].next)
	{
		int e=ed[i].e;
		if(e==fa) continue;
		dfs(e,x);
		f[x]+=f[e];
	}
	for(int i=first[x];i;i=ed[i].next)
	{
		int e=ed[i].e;
		int val=ed[i].val;
		if(e==fa) continue;
		s.insert(g[e]+val);
	}
	while(s.size())
	{
		int now=*s.rbegin();
		if(now>=mid)
		{
			it=s.find(now);
			f[x]++;
			s.erase(it);
		}
		else break;
	}
	while(s.size())
	{
		int now=*s.begin();
		s.erase(s.begin());
		it=s.lower_bound(mid-now);
		if(it==s.end())
		g[x]=now;
		else 
		{
			f[x]++;
			s.erase(it);
		}
	}
}
signed main()
{
	int l=0,r=1e8;
	n=read(),m=read();
	for(int i=1;i<=n-1;i++)
	{
		int x=read(),y=read(),z=read();
		add_edge(x,y,z);
		add_edge(y,x,z);

		l=min(l,z);
		r+=z;
	}
	while(l<=r)
	{
		init();
		mid=(l+r)>>1;
		dfs(1,0);
		if(f[1]>=m) ans=max(ans,mid),l=mid+1;
		else r=mid-1;
	}
	cout<<ans<<'\n';
	return 0;
}
```

