### T3 逛公园

#### 思路

用 $dfs(x,len)$ 表示到第 $x$ 个点 ，现在还可以走 $len$ 个距离

所以 $dfs(x,len)=dfs(y,dis[x]+len-dis[y]-z )$ 

其中 $y \in son(x)$

我们标记走过的节点，如果第第二次经过的话，也就是有一个零环，那我们就返回负一

然后我们枚举下一个位置，看是否能不能继续走，如果找到零环的话那就返回呗

如果找到的话，说明找到了第一个点，我们建的是反图，要从后往前走

然后就用死了的spfa

好难啊

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <queue>
#define int long long
using namespace std;
const int maxn=100005;
int T;
int dis[maxn],f[maxn][51];
int n,m,k,p;
bool vis[maxn][51];
struct node{
	int to,value;
};
vector<node> g1[maxn],g2[maxn];
int dfs(int x,int len)
{
	int ans=0;
	if(len<0||len>k)
	return 0;
	if(vis[x][len])
	{
		vis[x][len]=false;
		return -1;
	}
	if(f[x][len]!=-1) 
	return f[x][len];
	vis[x][len]=true;
	for(int i=0;i<g2[x].size();i++)
	{
		int y=g2[x][i].to;
		int z=g2[x][i].value;
		int val=dfs(y,dis[x]+len-dis[y]-z);
		if(val==-1)
		{
			vis[x][len]=false;
			return -1;
		}
		ans=(ans+val)%p;
	}
	vis[x][len]=false;
	if(x==1&&len==0) 
	ans++;
	f[x][len]=ans;
	return ans;
}
void spfa()
{
	memset(dis,0x3f3f3f,sizeof(dis));
	memset(f,-1,sizeof(f));
	queue<int> q;
	q.push(1);
	dis[1]=0;
	while(q.size())
	{
		int x=q.front(); 
		q.pop();
		for(int i=0;i<g1[x].size();i++)
		{
			int y=g1[x][i].to;
			int z=g1[x][i].value;
			if(dis[y]>dis[x]+z)
			{
				dis[y]=dis[x]+z;
				q.push(y);
			}
		}
	}
}

int sol()
{
	cin>>n>>m>>k>>p;
	for(int i=1;i<=n;i++)
	{
		g1[i].clear(); 
		g2[i].clear();
	}
    while(m--)
	{
    	int x,y,z;
    	cin>>x>>y>>z;
        g1[x].push_back(node{y,z});
        g2[y].push_back(node{x,z});
    }
	spfa();
	int ans=0;
	for(int i=0;i<=k;i++)
	{
		int val=dfs(n,i);
		if(val==-1) 
		return -1;
		ans=(ans+val)%p;
	}
	return ans;
}
signed main()
{
	cin>>T;
	while(T--) 
	cout<<sol()<<'\n';
	return 0;
}
```

