### T3 愤怒的小鸟

#### 思路

搜索，或者状压

如果是我这种蒟蒻的话

搜索更好理解一些

我们可以对于当前小鸟，尝试搜索这只小鸟是否在已有的抛物线上

如果在的话，说明这个小鸟不用再多占一个抛物线，所以直接退出

如果不在的话，我们就要考虑这个小鸟和当前其他还没有匹配的小鸟是不是可以组成一个抛物线

如果横坐标相同，显然不行，因为函数是一一对应的映射

然后用公式算一个函数 $y=ax^2+bx$ 的 $a,b$

推导一下：

设函数上两点 $(x_1,y_1),(x_x,y_2)$

则 
$
\begin{cases} 
ax_1^2+bx_1=y_1 ①
\\
ax_2^2+bx_2=y_2②
\end{cases}
$
$①\times x_2-② \times x_1$ 得
$
a(x_1^2x_2-x_2^2x_1)=y_1x_2-y_2x_1
$
移项
$
a= \dfrac {y_1x_2-y_2x_1} {x_1^2x_2+x_2^2x_1}③
$
$③$ 带入 $①$ 或者 $②$
$
b= \dfrac {y_1-ax_1^2} {x_1}④
$
然后我们就可以求出来这个函数的 $a,b$

如果 $a<0$ 说明可以构成抛物线，所以我们将这个抛物线加入，把这个猪删除，然后搜索，然后回溯

反之，我们就把这头猪加入单独成为抛物线的行列

然后搜索的时候，如果结果已经大于当前答案了，那么剪个枝直接回去，及时止损

这样就做完了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <string>
#include <cstring>
#include <cmath>
using namespace std;
const int maxn=20;
const double eps=1e-7;
int n,m,ans;
double x[maxn],y[maxn];
double pa[maxn],pb[maxn];
double dx[maxn],dy[maxn];
bool check(double x,double y)
{
	return fabs(x-y)<eps;
}
void dfs(int dep,int cnt,int re)
{
	if(cnt+re>=ans) return ;
	if(dep>n)
	{
		ans=cnt+re;
		return ;
	}
	bool flag=false;
	for(int i=1;i<=cnt;i++)
	{
		if(check(pa[i]*x[dep]*x[dep]+pb[i]*x[dep],y[dep]))
		{
			dfs(dep+1,cnt,re);
			flag=true;
			break;
		}
	}
	if(!flag)
	{
		for(int i=1;i<=re;i++)
		{
			if(check(x[dep],dx[i])) continue;
			double a=(y[dep]*dx[i]-dy[i]*x[dep])/(x[dep]*x[dep]*dx[i]-dx[i]*dx[i]*x[dep]);
			double b=(y[dep]-x[dep]*x[dep]*a)/x[dep];
			if(a<0)
			{
				pa[cnt+1]=a;
				pb[cnt+1]=b;
				double p=dx[i],q=dy[i];
				for(int j=i;j<re;j++)
				{
					dx[j]=dx[j+1];
					dy[j]=dy[j+1];
				}
				dfs(dep+1,cnt+1,re-1);
				for(int j=re;j>i;j--)
				{
					dx[j]=dx[j-1];
					dy[j]=dy[j-1];
				}
				dx[i]=p,dy[i]=q;
			}
		}
		dx[re+1]=x[dep],dy[re+1]=y[dep];
		dfs(dep+1,cnt,re+1);
	}
}
int T;
int main()
{
	cin>>T;
	while(T--)
	{
		cin>>n>>m;
		for(int i=1;i<=n;i++)
		cin>>x[i]>>y[i];
		ans=10000;
		dfs(1,0,0);
		cout<<ans<<'\n';
	}
	return 0;
}
```

