	vis[x]=true;
	for(int i=1;i<25;i++)
	fa[x][i]=fa[fa[x][i-1]][i-1];
	for(int i=first[x];i>0;i=ed[i].next)
	{
		int v=ed[i].e;
		if(!vis[v])
		{
			fa[v][0]=x;
			dis[v]=dis[x]+ed[i].val;
			dfs(v,x,depth+1);
		}
	}
}
int get_lca(int x,int y)
{
	if(dep[x]<dep[y]) swap(x,y);
	int t=dep[x]-dep[y];
	for(int i=0;i<25;i++)
		if((1<<i)&t) x=fa[x][i];
	if(x==y) return x;
	for(int i=24;i>=0;i--)
	{
		if(fa[x][i]!=fa[y][i])
		x=fa[x][i],y=fa[y][i];
	}
	return fa[x][0];
}
int tmp[maxn];
bool check(int x)
{
	int cnt=0,ans=0;
	memset(tmp,0,sizeof(tmp));
	for(int i=1;i<=m;i++)
	{
		if(p[i].dist>x)
		{
			tmp[p[i].u]++;
			tmp[p[i].v]++;
			tmp[p[i].lca]-=2;
			ans=max(ans,p[i].dist-x);
			cnt++;
		}
	}
	if(cnt==0) return true;
	for(int i=n;i>=1;i--) 
	tmp[fa[num[i]][0]]+=tmp[num[i]];
	for(int i=2;i<=n;i++) 
		if(tmp[i]==cnt&&dis[i]-dis[fa[i][0]]>=ans) 
		return true;
	return false;
}

signed main()
{
	cin>>n>>m;
	for(int i=1;i<=n-1;i++)
	{
		int x,y,z;
		cin>>x>>y>>z;
		add_edge(x,y,z);
		add_edge(y,x,z);
		s+=z;
	}
	dis[0]=0;
	fa[0][0]=0;
	dep[0]=1;
	dfs(1,0,1);
	for(int i=1;i<=m;i++)
	{
		cin>>p[i].u>>p[i].v;
		p[i].lca=get_lca(p[i].u,p[i].v);
		p[i].dist=dis[p[i].u]+dis[p[i].v]-2*dis[p[i].lca];
	}
	int l=0,r=s;
	while(l<r)
	{
		int mid=(l+r)>>1;
		if(check(mid)) 
		r=mid;
		else 
		l=mid+1;
	}
	cout<<l<<'\n';
	return 0;
}
```

