### T2 联合权值

#### 思路

我们可以发现，我们对于每个点可以枚举两个出点，这样距离就为2，然后我们枚举找到两个权值最大的点，这两个点产生的联合权值就最大

那么这两个点的联合权值怎么算呢

我们可以使用平方和公式 
$
(a+b)^2=a^2+2ab+b^2
$
移项，就得到了
$
2ab=(a+b)^2-(a^2+b^2)
$
对于多个点，我们也可以推出高维的结论

和这个平方差的结论类似

然后我们就直接搜就可以了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int mod=10007;
const int maxn=200005;
struct edge{
	int e,next;
}ed[maxn*2];
int en,first[maxn];
void add_edge(int s,int e)
{
	en++;
	ed[en].next=first[s];
	first[s]=en;
	ed[en].e=e;
}
int n;
int val[maxn];
int ans1,ans2;
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n-1;i++)
	{
		int u,v;
		cin>>u>>v;
		add_edge(u,v);
		add_edge(v,u);
	}
	for(int i=1;i<=n;i++)
	cin>>val[i];
	for(int i=1;i<=n;i++)
	{
		int mx1=-99999,mx2=-99999;
		int sq=0,sum=0;
		for(int j=first[i];j;j=ed[j].next)
		{
			int e=ed[j].e;
			if(mx1<val[e])
			{
				mx2=mx1;
				mx1=val[e];
			}
			else if(mx2<val[e])
			{
				mx2=val[e];
			}
			sum=(sum+val[e])%mod;
			sq=(sq+val[e]*val[e]%mod);
		}
		sum=sum*sum%mod;
		ans2=(ans2+sum-sq+mod)%mod;
		ans1=max(ans1,mx1*mx2);
	}
	cout<<ans1<<" "<<ans2<<'\n';
	return 0; 
}
```

### T3 飞扬的小鸟

#### 思路

动态规划，一个背包类的模板

设 $f[i][j]$ 表示横坐标为 $i$ 的时候，高度为 $j$  ，这个时候最小点击次数是多少

上升的时候呢，就是一个完全背包

下降的时候就是01背包

如果纵坐标超过 $m$ 的话，那我们就直接把纵坐标变成 $m$​

From:https://www.luogu.com.cn/blog/JOE/solution-p1941

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=10005;
const int INF=0x3f3f3f; 
int n,m,k;
int x[maxn],y[maxn];
int down[maxn],up[maxn];
int f[maxn][2005];
bool flag[maxn];
int main()
{
	cin>>n>>m>>k;
	for(int i=1;i<=n;i++)
	{
		cin>>x[i]>>y[i];
		up[i]=m;
		down[i]=1;
	}
	for(int i=1;i<=k;i++)
	{
		int a,b,c;
		cin>>a>>b>>c;
		flag[a]=1;
		down[a]=b+1;
		up[a]=c-1;
	}
	memset(f,0x3f3f3f,sizeof(f));
	for(int i=1;i<=m;i++)
	f[0][i]=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=x[i]+1;j<=x[i]+m;j++)
			f[i][j]=min(f[i-1][j-x[i]]+1,f[i][j-x[i]]+1);
		for(int j=m+1;j<=x[i]+m;j++)
			f[i][m]=min(f[i][j],f[i][m]);
		for(int j=1;j<=m-y[i];j++)
			f[i][j]=min(f[i][j],f[i-1][j+y[i]]);
		for(int j=1;j<down[i];j++)
			f[i][j]=INF;
		for(int j=up[i]+1;j<=m;j++)
			f[i][j]=INF; 
	}
	int ans=INF;
	for(int i=1;i<=m;i++)
	ans=min(ans,f[n][i]);
	if(ans<INF)
	{
		cout<<1<<'\n'<<ans<<'\n';
		return 0;
	}
	int i,j;
	for(i=n;i>=1;i--)
	{
		for(j=1;j<=m;j++)
		if(f[i][j]<INF)
		break;
		if(j<=m)
		break;
	}
	ans=0;
	for(j=1;j<=i;j++)
	if(flag[j])
	ans++;
	cout<<0<<'\n'<<ans<<'\n';
	return 0;
}
```

