### T2 寻找道路

#### 思路

本来一个是一个裸的单源最短路径

没想到还是穿了个内裤的

首先我们要直接或者间接与终点连通的，所以我们建一个反图，标记终点可以到哪些点

然后我们如果标记到起点的话，说明可以，反之不可以

如果可以的话，我们在一开始的时候因为也要建正图

所以从起点开始做一个单源最短路径就好了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <queue>
using namespace std;
const int maxn=300005;
struct edge{
	int e,next;
}ed[maxn*2];
int en,first[maxn];
void add_edge(int s,int e)
{
	en++;
	ed[en].next=first[s];
	first[s]=en;
	ed[en].e=e;
}
int n,m,s,t;
int d[maxn];
bool qyj[maxn],qy[maxn],yj[maxn];
void spfa(int s)
{
	memset(qyj,false,sizeof(qyj));
	memset(d,0x3f3f3f,sizeof(d));
	queue <int> q;
	q.push(s);
	qyj[s]=true;
	d[s]=0;
	while(q.size()) 
	{
		int x=q.front();
		q.pop();
		qyj[s]=false;
		for(int i=first[x];i;i=ed[i].next)
		{
			int e=ed[i].e;
			if(d[e]>d[x]+1&&qy[e])
			{
				d[e]=d[x]+1;
				if(!qyj[e])
				{
					qyj[e]=true;
					q.push(e);
				}
			}
		}
	}
}
void bfs(int t)
{
	memset(qyj,false,sizeof(qyj));
	queue <int> q;
	q.push(t);
	qy[t]=qyj[t]=true;
	while(q.size())
	{
		int x=q.front();
		q.pop();
		for(int i=first[x];i;i=ed[i].next)
		{
			int e=ed[i].e;
			if(!qyj[e])
			{
				qyj[e]=true;
				qy[e]=true;
				q.push(e);
			}
		}
	}
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int x,y;
		cin>>x>>y;
		add_edge(x,y);
	}
	cin>>s>>t;
	bfs(t);
	for(int i=1;i<=n;i++)
	yj[i]=qy[i];
	for(int i=1;i<=n;i++)
	{
		if(!yj[i])
		{
			for(int j=first[i];j;j=ed[j].next)
			{
				int e=ed[j].e;
				if(yj[e])
				yj[e]=false;
			}
		}
	}
	spfa(t);
	if(d[s]>=0x3f3f3f)
	cout<<-1<<'\n';
	else
	cout<<d[s]<<'\n';
	return 0;
}

```

### T3 解方程

#### 思路

大概就是依次尝试一下成不成立吧

我们我们在输入的时候用秦九昭算法来处理一下

我们考虑到，我们每一个系数都模一个质数这样就好了

为什么呢，实际上比较玄学

但是有一定的严谨性

我们可以对多个质数取模，这样就能大大降低错误的概率

然后算这个表达式的时候也是边乘边模就好了，记住，要模之前的那个数字

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#define int long long
using namespace std;
const int p=1000000007;
const int maxn=1005;
int a[maxn],ans[1000003];
int n,m;
int en;
bool t=true;
inline int read()
{
	int x=0,f=1;
	char c=getchar(); 
	while(c<'0'||c>'9') 
	{
		if(c=='-')
		f=-1;
		c=getchar();
	}
	while(c>='0'&&c<='9')
	{
		x=((x<<1)+(x<<3)+c-'0')%p;
		c=getchar();
	}
	return x*f;
}
int f(int x)
{
	int res=0;
	for(int i=n;i>=1;i--)
	res=((res+a[i])*x)%p;
	res=(res+a[0])%p;
	return res==0;
}
signed main()
{
	n=read(),m=read();
	for(int i=0;i<=n;i++)
	a[i]=read();
	for(int i=1;i<=m;i++)
	{
		if(f(i))
		{
			t=false;
			ans[0]++;
			en++;ans[en]=i;
		}
	}
	if(t)
	{
		cout<<ans[0]<<endl;
		return 0;
	}
	cout<<ans[0]<<endl;
	for(int i=1;i<=en;i++)
	cout<<ans[i]<<endl;
	return 0;
}
```

