### T2 火柴排队

#### 思路

值域树状数组

我们要使得 $\sum (a_i-b_i)^2$ 最小

变形一下
$
\sum (a_i^2+2a_ib_i+b_i^2)
\\= \sum (a_i^2+b_i^2)+\sum2a_ib_i
$
我们发现 $\sum (a_i^2+b_i^2)$ 是一个定值，所以我们只需要让 $\sum 2a_ib_i$ 最小就好了

如何让两个数列的 $2a_ib_i$ 最小呢

我们可以让两个序列中的数字各自标上排名

然后如果两个数列的数字的排名相对应，我们就可以让它最小

比如说

`2 3 1 4`

`3 2 1 4`

我们只需要交换一次

再比如

`1 3 4 2`

`1 7 2 4`

我们让他们对应，也就是将第二个序列中的 `7 2 4` 变成 `4 7 2` ，交换两次

那我们就以第一个数列为基准，对于这个数列我们就可以离散化一下，表示排名，然后建立两个数列间的类似于最长公共子序列的 $O(n^2)$ 的做法的方法来建立一一映射的关系

值域树状数组求逆序对即可

这样就做完了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=500005;
const int mod=99999997;
int tree[maxn],rank[maxn],n;
long long ans;
struct point{
	int num,val;
}a[maxn],b[maxn];
int lowbit(int x)
{
	return x&(-x);
}
bool cmp(point q,point w)
{
	if(q.val==w.val)
	return q.num<w.num;
	return q.val<w.val;
}
void add(int x,int y)
{
	for( ;x<=n;x+=lowbit(x)) tree[x]+=y,tree[x]%=mod;
}
int ask(int x)
{
	int ans=0;
	for( ;x;x-=lowbit(x)) ans+=tree[x],ans%=mod;
	return ans;
}
int main()
{
	std::ios::sync_with_stdio(false);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].val;
		a[i].num=i;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>b[i].val;
		b[i].num=i;
	}
	sort(a+1,a+1+n,cmp);
	sort(b+1,b+1+n,cmp);
	for(int i=1;i<=n;i++)
	rank[a[i].num]=b[i].num;
	for(int i=1;i<=n;i++)
	{
		add(rank[i],1);
		ans+=(i-ask(rank[i]));
		ans%=mod;
	}
	cout<<ans<<endl;
	return 0;
}
```

### T3 货车运输

#### 思路

最大生成树 + LCA

我们要求的是每一条路径中最小边的最大值，这个最大值肯定会加入最大生成树，所以我们做一个最大生成树

然后，对于这棵树，我们倍增预处理每一条边到自己的 $k$ 级祖先的答案，然后我们用倍增 $lca$ 来合并答案

然后就没了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <cmath> 
using namespace std; 

const int maxn=10005;
const int INF=999999999;

struct edge1{  
    int x,y,dis;
}ed1[50005]; 
struct edge2{
    int to,next,w;
}ed2[100005];
int cnt,n,m,head[maxn],deep[maxn],f[maxn],fa[maxn][21],w[maxn][21];
bool vis[maxn]; 
void add_edge(int from, int to, int w)
{
    ed2[++cnt].next=head[from];
    ed2[cnt].to=to;
    ed2[cnt].w=w;
    head[from]=cnt;
    return ;
}

bool cmp(edge1 x, edge1 y)
{
    return x.dis>y.dis; //将边权从大到小排序 
}

int find(int x)
{
    if(f[x]!=x) f[x]=find(f[x]);
    return f[x];
}

void kruskal()
{
    sort(ed1+1,ed1+m+1,cmp); 
    for(int i=1;i<=n;i++)
    f[i]=i;
    for(int i=1; i<=m; i++)
    if(find(ed1[i].x)!=find(ed1[i].y))
	{
        f[find(ed1[i].x)]=find(ed1[i].y);
        add_edge(ed1[i].x, ed1[i].y, ed1[i].dis);
        add_edge(ed1[i].y, ed1[i].x, ed1[i].dis); 
    }
    return ;
}

void dfs(int node)
{
    vis[node]=true;
    for(int i=head[node]; i; i=ed2[i].next)
	{
        int to=ed2[i].to;
        if(vis[to]) continue;
        deep[to]=deep[node]+1;
        fa[to][0]=node;
        w[to][0]=ed2[i].w;
        dfs(to);
    }
    return ;
}

int lca(int x, int y)
{
    if(find(x)!=find(y)) return -1;
    int ans=INF;
    if(deep[x]>deep[y]) swap(x,y);
    for(int i=20; i>=0; i--)
        if(deep[fa[y][i]]>=deep[x])
		{
            ans=min(ans, w[y][i]);
            y=fa[y][i];
        }
    if(x==y) return ans;
    for(int i=20; i>=0; i--)
        if(fa[x][i]!=fa[y][i])
		{
            ans=min(ans, min(w[x][i], w[y][i]));
            x=fa[x][i]; 
            y=fa[y][i];
        }
    ans=min(ans, min(w[x][0], w[y][0]));
    return ans;
}

int main()
{
    int x,y,z,q;
    cin>>n>>m;
    for(int i=1; i<=m; i++)
	{
        cin>>x>>y>>z;
        ed1[i].x=x;
        ed1[i].y=y;
        ed1[i].dis=z;
    }
    kruskal();
    for(int i=1;i<=n;i++)
        if(!vis[i])
		{
            deep[i]=1; 
            dfs(i);
            fa[i][0]=i;
            w[i][0]=INF;
        }
    for(int i=1;i<=20;i++)
        for(int j=1;j<=n;j++)
		{
            fa[j][i]=fa[fa[j][i-1]][i-1]; 
            w[j][i]=min(w[j][i-1], w[fa[j][i-1]][i-1]);
        }
    cin>>q;
    for(int i=1; i<=q; i++)
	{
		cin>>x>>y;
        cout<<lca(x,y)<<endl;
    }
    return 0;
} 
