# 【解题报告】洛谷P1096 Hanoi双塔问题

### 题目链接

https://www.luogu.com.cn/problem/P1096

### 思路

一个普通的汉诺塔的变形问题

策略和普通的一样

上面的 $(n-1) \times 2$ 层先移到B上然后把最后两个移动到C上，最后把B上面的移动到C上

设 $f[i]$ 表示把 $2i$ 层完成的步骤

然后就有 $f[i]=2 \times f[i-1]+2$ 边界是 $f[1]=2$

然后发现数据最后比较大，"数据之大，long long装不下"

然后我们加一个高精度就完了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=2500;
char s[maxn];
struct gaojing{
	int n,z[maxn];
	gaojing()
	{
		n=1;
		memset(z,0,sizeof(z));
	}
	void init()
	{
		scanf("%s",s+1);
		int len=strlen(s+1);
		reverse(s+1,s+len+1);
		n=len;
		for(int i=1;i<=n;i++)
		z[i]=s[i]-'0';
	}
	void print()
	{
		for(int i=n;i>=1;i--)
		cout<<z[i];
	}
};
gaojing operator+(const gaojing &a,const gaojing &b)
{
	gaojing c;
	c.n=max(a.n,b.n);
	for(int i=1;i<=c.n;i++)
	c.z[i]=a.z[i]+b.z[i];
	for(int i=1;i<=c.n;i++)
	{
		c.z[i+1]+=c.z[i]/10;
		c.z[i]=c.z[i]%10;
	}
	if(c.z[c.n+1]!=0) c.n++;
	return c;
}
gaojing operator*(const gaojing &a,const gaojing &b)
{
	gaojing c;
	c.n=a.n+b.n;
	for(int i=1;i<=a.n;i++)
	{
		for(int j=1;j<=b.n;j++)
		c.z[i+j-1]+=a.z[i]*b.z[j]; 
	}
	for(int i=1;i<=c.n;i++)
	{
		c.z[i+1]+=c.z[i]/10;
		c.z[i]=c.z[i]%10;
	}
	while(c.n!=1&&c.z[c.n]==0) c.n--;
	return c;
}
int n;
gaojing f[205];
int main()
{
	cin>>n;
	gaojing two;
	two.n=1;
	two.z[1]=2;
	f[1]=two;
	for(int i=2;i<=n;i++)
	f[i]=two*f[i-1]+two;
	f[n].print();
	return 0;
}
```

# 【解题报告】洛谷P1043 数字游戏

### 题目链接

https://www.luogu.com.cn/problem/P1043

### 思路

动态规划，类似于能量项链和石子合并之类的

首先这是一个环，我们用常见的破环成链的技巧——开双倍数组来做

然后我们设置状态 $f[i][j]$ 表示前 $i$ 个数字分成 $j$ 个部分可以得到的最小值是多少

则有
$
f[i][j]=min\{f[i-k][j-1]\times s[i-k+1][i] \},0 \le k \le i
$
同理，我们可以设 $g[i][j]$ 表示上述的最大值
$
g[i][j]=min\{g[i-k][j-1]\times s[i-k+1][i] \},0 \le k \le i
$
但是有一个小细节要处理一下

我们在模的时候负数模一个数字还是负数

但是根据题目描述，它要变成正数

所以我们的对于小于0的加一个10就好了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#define int long long
using namespace std;
const int maxn=105;
int n,m;
int a[maxn];
int s[maxn][maxn],f[maxn][maxn],g[maxn][maxn];
int minn=1e9,maxx=-1e9;

signed main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		a[i+n]=a[i];
	}
	for(int x=0;x<=n;x++)
	{
		for(int i=x+1;i<=x+n;i++)
		{
			for(int j=i;j<=x+n;j++)
			s[i][j]=s[i][j-1]+a[j];
		}
		for(int i=x+1;i<=x+n;i++)
		{
			for(int j=i;j<=x+n;j++)
			{
				s[i][j]%=10;
				if(s[i][j]<0) 
				s[i][j]+=10;
			}
		}
		for(int i=x+1;i<=x+n;i++)
		{
			for(int j=1;j<=m;j++)
			{
				f[i][j]=1e9;
				g[i][j]=-1e9;
			}
		}
		for(int i=x+1;i<=x+n;i++)
		f[i][0]=g[i][0]=s[x+1][i];
		for(int j=1;j<=m;j++)
		{
			for(int i=j+1+x;i<=n+x;i++)
			{
				for(int k=x+1;k<i;k++)
				{
					f[i][j]=min(f[i][j],f[k][j-1]*s[k+1][i]);
					g[i][j]=max(g[i][j],g[k][j-1]*s[k+1][i]);
				}
			}
		}
		maxx=max(maxx,g[x+n][m-1]);
		minn=min(minn,f[x+n][m-1]);
	} 
	cout<<minn<<'\n'<<maxx<<'\n';
	return 0;
}
```

# 【解题报告】洛谷P1038 神经网络

### 题目链接

https://www.luogu.com.cn/problem/P1038

### 思路

一看，就是拓扑排序

这个相当于拓扑排序的板子题目吧qaq

然后我们就直接做了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <queue>
#define int long long
using namespace std;
const int maxn=105;
struct edge{
	int e,next,val;
}ed[maxn*maxn];
int en,first[maxn];
void add_edge(int s,int e,int val)
{
	en++;
	ed[en].next=first[s];
	first[s]=en;
	ed[en].e=e;
	ed[en].val=val;
}
int n,p;
int C[maxn],U[maxn];
int st[maxn];
bool vis[maxn],out[maxn];
queue <int> q;
signed main()
{
	cin>>n>>p;
	for(int i=1;i<=n;i++)
	{
		vis[i]=out[i]=false;
		cin>>C[i]>>U[i];
		if(C[i]>0)
		{
			q.push(i);
			vis[i]=true;
		}
		else
		C[i]-=U[i];
	}
	for(int i=1;i<=p;i++)
	{
		int x,y,z;
		cin>>x>>y>>z;
		add_edge(x,y,z);
		out[x]=true;
	}
	while(q.size())
	{
		int x=q.front();
		q.pop();
		if(C[x]<0) continue;
		for(int i=first[x];i;i=ed[i].next)
		{
			int e=ed[i].e;
			int val=ed[i].val;
			C[e]+=(val*C[x]);
			if(!vis[e])
			{
				vis[e]=true;
				q.push(e);
			} 
		}
	}
	bool flag=false;
	for(int i=1;i<=n;i++)
	{
		if(!out[i]&&C[i]>0)
		{
			flag=true;
			cout<<i<<" "<<C[i]<<'\n';
		}
	}
	if(!flag)
	cout<<"NULL"<<'\n';
	return 0;
}
```

# 【解题报告】洛谷P6475 建设城市

### 题目链接

https://www.luogu.com.cn/problem/P6475

### 思路

考虑排列组合

- 如果两个分居左右

我们可以枚举一下两个楼房的高度,假设 $x<n<y$ ，那么 $x$ 左边有 $x-1$ 个楼房，右边有 $n-x$ 个楼房，我们设我们已经枚举 $x$ 的高度到 $i,1 \le i \le m$ ，然后左边 $x-1$ 个楼房就可以从 $i$ 个数字中选择递增的一段，也就是 $C_{i}^{x-1}$ 。右边也是 $m-i+1$ 个可选数字 我们可以选择一个递增的一段，也就是 $C_{m-i+1}^{n-x}$ 。

同理，我们可以对 $y$ 进行划分 

两个答案是 $C_{m-i+1}^{y-n-1}$ , $C_i^{2n-y}$

根据乘法原理，对于每个 $i$ 的方案数量就是这四个数字相乘

答案加起来就好了
$
ans=\sum_{i=1}^m (C_{i}^{x-1} \times C_{m-i+1}^{n-x} \times C_{m-i+1}^{y-n-1}\times C_i^{2n-y})
$

- 两个在同一边

  那就好办了，那就是他们中间都是一样高的

  答案就是 $C_m^n \times C_m^{n+x-y}$

但是，这道题目的核心并不是分析这个，这个小学生都能分析出来吧

我们要做的最难得就是求组合数，这个组合数非常大，我们直接求肯定会炸掉吧

即使用杨辉三角形也会复杂度爆炸吧

所以，请循其本 $C_n^m=\dfrac {n!} {m!(n-m)!}$

我们用一个阶乘，然后利用在模意义下的逆元就好了啊，我们可以用费马小定理来求逆元吧

然后就没有然后了

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#define int long long 
using namespace std;
const int maxn=200005;
const int mod=998244353;
int m,n,x,y;
int ans;
int fac[maxn],ifac[maxn];
int ksm(int a,int b)
{
	int res=1%mod;
	while(b)
	{
		if(b&1)
		res=res%mod*a%mod;
		a=a%mod*a%mod;
		b>>=1;
	}
	return res%mod;
}
int C(int m,int n)
{
	return fac[n+m-1]*ifac[n]%mod*ifac[m-1]%mod;
}
signed main()
{
	cin>>m>>n>>x>>y;
	fac[0]=1;
	for(int i=1;i<=m+n;i++)
	fac[i]=fac[i-1]*i%mod;
	ifac[m+n]=ksm(fac[m+n],mod-2);
	for(int i=m+n-1;~i;i--)
	ifac[i]=ifac[i+1]*(i+1)%mod;
	if(x<=n&&y>n)
	{
		for(int i=1;i<=m;i++)
		ans=(ans%mod+C(i,x-1)%mod*C(m-i+1,n-x)%mod*C(m-i+1,y-n-1)%mod*C(i,2*n-y)%mod+mod)%mod;		
	}
	else
	ans=C(m,n)*C(m,n+x-y)%mod;
	cout<<ans<<'\n';
	return 0;
}
```

# 【解题报告】洛谷P4138 挂饰

### 题目链接

https://www.luogu.com.cn/problem/P4138

### 思路

设 $f[i][j]$ 表示挂了前  $i$ 个挂饰，还剩下 $j$ 个挂的位置，可以得到的最大的喜悦值是多少

这就是一个背包
$
f[i][j]=max(f[i-1][j],f[i-1][max(j-c[i].a,0)+1]+c[i].b)
$
其中如果加上挂钩之后小于零了之后，那就只挂在手机上了，所以是还剩下一个的那种情况,然后观察状态转移方程可以使用滚动数组优化一下就可以了

```cpp
#include <iostream>
