		flag=true;
		sol=max(sol,calc());
		return ; 
	}
	int x=s[now].x;
	int y=s[now].y;
	if(a[x][y]==0)
	{
		for(int i=1;i<=9;i++)
		{
			int pos=get_g(x,y);
			if(!f[x][i]&&!g[y][i]&&!h[pos][i])
			{
				ans[x][y]=i;
				f[x][i]=g[y][i]=h[pos][i]=true;
				dfs(now+1);
				f[x][i]=g[y][i]=h[pos][i]=false;
			}
		}
	}
	else dfs(now+1);
}
int main()
{
	for(int i=1;i<=9;i++)
	{
		int cnt=0;
		for(int j=1;j<=9;j++)
		{
			cin>>a[i][j];
			if(a[i][j]==0) cnt++;
			else
			{
				int val=a[i][j];
				int pos=get_g(i,j);
				ans[i][j]=val;
				f[i][val]=true;
				g[j][val]=true;
				h[pos][val]=true;
			}
		}
		row[i].id=i;
		row[i].lcnt=cnt;
	}
	sort(row+1,row+1+9,cmp);
	int tot=0;
	for(int i=1;i<=9;i++)
	{
		for(int j=1;j<=9;j++)
		{
			s[++tot].x=row[i].id;
			s[tot].y=j;
		}
	}
	dfs(1);
	if(flag)
	cout<<sol<<'\n';
	else
	cout<<-1<<'\n';
	return 0;
}
