#include <string>
#include <vector>
using namespace std;
const int maxn=300005;
vector <int> val[maxn],tv[maxn];
int n,q;
int flag,lastans=0;
int main()
{
	freopen("array.in","r",stdin);
	freopen("array.out","w",stdout);
	cin>>n>>q>>flag;
	for(int i=1;i<=n;i++)
	{
		int v;
		cin>>v;
		val[i].push_back(v);
		tv[i].push_back(0);
	}
	for(int t=1;t<=q;t++)
	{
		int op,a,b;
		cin>>op>>a>>b;
		if(flag) 
		a^=lastans,b^=lastans;
		if(op==1)
		{
			val[a].push_back(b);
			tv[a].push_back(t);
		}
		else if(op==2)
		{
			int l=0,r=val[a].size()-1;
			int pos=0;
			while(l<=r)
			{
				int mid=(l+r)>>1;
				if(tv[a][mid]<=b)
				pos=mid,l=mid+1;
				else
				r=mid-1;
			}
			lastans=val[a][pos];
			cout<<lastans<<'\n';
