#include<bits/stdc++.h>
using namespace std;
inline int Abs(int x){return x<0?-x:x;}
const int dx[]={1,-1,0,0},dy[]={0,0,1,-1};
const int D=0,U=1,R=2,L=3;
const char dv[]={'D','U','R','L'};
