		for(int i=0;i<4;i++) {
			int nx=x+dx[i],ny=y+dy[i];
			if(nx<lx||nx>rx||ny<ly||ny>ry) continue;
			if(lstv[nx][ny]||flg[nx][ny]==0) continue;
			lstv[nx][ny]=i+1;
			qx[++ta]=nx;qy[ta]=ny;
		}
	}
/*	puts("--------");
	for(int i=lx;i<=rx;i++)
	{
		for(int j=ly;j<=ry;j++) cout<<flg[i][j]<<' ';
