## T3 函数调用

在赛场上我一度认为这道题目是最简单的

但是不是

这道题目看到标签说要用拓扑排序来着

然后拓扑排序一下

实际上对于每个操作进行处理，对于操作2，实际上我们可以看成若干个操作1，然后操作3也可以转化一下，然后我们就可以建一个函数调用关系的有向图，进行拓扑排序，看函数调用的顺序，然后我们对于每一个加法和乘法，看他们对于总的答案的贡献是多少，然后就可做了

参考代码

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <queue>
using namespace std;
const int maxn=100005;
const int mod=998244353;
int n,m,q;
int cnt[maxn];
int a[maxn];
int type[maxn],mul[maxn],add[maxn],pos[maxn];
int out1[maxn],out2[maxn];
vector<int> g1[maxn],g2[maxn];
void topo1()
{
	queue <int> q;
	for(int i=0;i<=m;i++)
	{
		out1[i]=g2[i].size();
		if(out1[i]==0)
		q.push(i);
	}
	while(q.size())
	{
		int x=q.front();
		q.pop();
		for(int i=0;i<g1[x].size();i++)
		{
			int e=g1[x][i];
			mul[e]=1ll*mul[e]*mul[x]%mod;
			out1[e]--;
			if(out1[e]==0)q.push(e);
		}
	}
}
void topo2()
{
	queue <int> q;
	for(int i=0;i<=m;i++)
	{
		out2[i]=g1[i].size();
		if(out2[i]==0)
		q.push(i);
	}
	while(q.size())
	{
		int x=q.front();
		int tag=1;
		q.pop();
		for(int i=g2[x].size();i>0;--i)
		{
			int e=g2[x][i-1];
			cnt[e]=(cnt[e]+1ll*cnt[x]*tag)%mod;
			tag=1ll*tag*mul[e]%mod;
			out2[e]--;
			if(out2[e]==0)
			q.push(e);
		}
	}
}
int main()
{
	std::ios::sync_with_stdio(false);
	cin>>n;
	for(int i=1;i<=n;i++)
	cin>>a[i];
	cin>>m;
	mul[0]=1;
	for(int i=1;i<=m;i++)
	{
		cin>>type[i];
		if(type[i]==1)
		{
			mul[i]=1;
			cin>>pos[i]>>add[i];
		}
		if(type[i]==2)
		cin>>mul[i];
		if(type[i]==3)
		{
			mul[i]=1;
			int c;
			cin>>c;
			for(int j=0;j<c;++j)
			{
				int e;
				cin>>e;
				g1[e].push_back(i);
				g2[i].push_back(e);
			}
		}
	}
	cin>>q;
	cnt[0]=1;
	while(q--)
	{
		int x;
		cin>>x;
		g1[x].push_back(0);
		g2[0].push_back(x);
	}
	topo1();
	topo2();
	for(int i=1;i<=n;i++)
	a[i]=1ll*a[i]*mul[0]%mod;
	for(int i=1;i<=m;i++)
	{
		if(type[i]==1)
		a[pos[i]]=(a[pos[i]]+1ll*cnt[i]*add[i])%mod;
	}
	for(int i=1;i<=n;i++)
	cout<<a[i]<<" ";
	return 0;
}
```

## T4 贪吃蛇

讲一个笑话，这是我当初以为整场比赛第二简单的题目

然后我就和这道题目搏斗，与这道题目抗争

最终的结果是我壮烈牺牲

这道题虽然用我的申必贪心方法，样例都能过，但是最后还是爆零了

然后现在看了题解之后，还是有一点懵的

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=1000005;
const int inf=1e9;
int T,n,a[maxn];
pair <int,int> q1[maxn],q2[maxn];
int l1,r1,l2,r2;
pair <int,int> get_max()//取最大蛇 
{
	if(r1==l1)
	return q2[l2++];
	else if(r2==l2)
	return q1[--r1];
	else if(q2[l2]>q1[r1-1])
	return q2[l2++];
	else return q1[--r1];
}
pair <int,int> get_min()//取最小 
{
	if(l1==r1)
	return q2[--r2];
	else if(r2==l2)
	return q1[l1++];
	else if(q2[r2-1]<q1[l1])
	return q2[--r2];
	else return q1[l1++];
}
pair <int,int> Min(pair <int,int> x,pair <int,int> y)
{
	return x<y?x:y;
}
inline void solve()
{
	l1=r1=l2=r2=0;
	for(int i=1;i<=n;++i)
	q1[r1++]=make_pair(a[i],i);
	int flag=0,cnt=0,alf=0;
	while(1)
	{
		cnt++;
		pair <int,int> x=get_min(),y=get_max();
		pair <int,int> z=Min((l1<r1?q1[l1]:make_pair(inf,-inf)),(l2<r2?q2[r2-1]:make_pair(inf,-inf)));
		y.first-=x.first;
		if(y>z||cnt==n-1)
		{
			if(flag)
			{
				cout<<n-(flag-(alf&1))<<'\n';
				return ;
			}
			if(cnt==n-1)
			{
				cout<<1<<'\n';
				return ;
			}
			q2[r2++]=y;
		}
		else 
		{
			alf++;
			if(!flag)
			flag=cnt;
			q2[r2++]=y;
		}
	}
}
int main()
{
	cin>>T;
	T--;
	cin>>n;
	for(int i=1;i<=n;i++)
	cin>>a[i];
	solve();
	while(T--)
	{
		int k;
		cin>>k;
		for(int i=1;i<=k;i++)
		{
			int x;
			cin>>x;
			cin>>a[x];
		}
		solve();
	}
	return 0;
}
```

