每个测试点的具体限制见下表：

| 测试点编号  | $n \le$ | $d_i, e_j \le$ |                  特殊限制                   |
| :---------: | :-----: | :------------: | :-----------------------------------------: |
|     $1$     |  $12$   |    ${10}^5$    |                     无                      |
| $2 \sim 3$  |  $100$  |    ${10}^9$    |                     无                      |
| $4 \sim 5$  | $1000$  |     $1000$     | $m = n - 1$，且每个学员的朋友数量不超过 $2$ |
| $6 \sim 7$  | $1000$  |    ${10}^9$    | $m = n - 1$，且每个学员的朋友数量不超过 $2$ |
| $8 \sim 10$ | $2000$  |    ${10}^9$    |                     无                      |

### 思路

目标是在树上选一个最大点集 $S$ ，使得 $S$ 的导出子图由一些大小大于等于 $2$ 的联通块构成 ，且权值和小于等于 $e_i$ 。

考虑用树形dp解决这一问题，

- 设 $f_{x,i,0}$ 表示 $x$ 子树，选了合法的 $i$ 个点， $x$ 点没被选中的最小代价

- 设 $f_{x,i,1}$ 表示 $x$ 子树，选了合法的 $i$ 个点， $x$ 点被选中，且已经确定有儿子（联通块等于 $2$ ），的最小代价

- 设 $f_{x,i,2}$ 表示 $x$ 子树，选了合法的 $i$ 个点， $x$ 点被选中，但是 $x$ 的儿子目前没被选中的最小代价

转移就是考虑儿子 $v$ 有没有被选中，这里还要考虑在 $x$ 处把 $v$ 改成选中的情况（若 $v$ 没有选中任何儿子，这个子状态本来是非法的）。

求完每个案后最后一起背包到 $g$ 中，注意 $g$ 要从后往前取 $min$ ，考虑选择点个数为 $3$ 的方案有可能劣于选择点个数为 $4$ 的方案（~~这里感谢粉兔的大样例~~）。

最后查询答案就在 $g$ 上二分即可，复杂度为 $O(n^2+q \log n)$​ 。

```cpp
#include <cstdio>
#include <algorithm>
#include <vector>

typedef long long LL;
const LL Inf = 0x3f3f3f3f3f3f3f3f;
const int MN = 2005;

int N, M, D[MN];
std::vector<int> G[MN];

inline void chkmin(LL &x, LL y) { x = x < y ? x : y; }
void Merge(LL (*fu)[3], int &n, LL (*fv)[3], int m) {
	static LL g[MN][3];
	for (int i = 0; i <= n + m; ++i)
		for (int p = 0; p < 3; ++p)
			g[i][p] = Inf;
	for (int i = 0; i <= n; ++i)
		for (int j = 0; j <= m; ++j) {
			LL mn02 = std::min(fv[j][0], fv[j][2]);
			chkmin(g[i + j][0], fu[i][0] + std::min(mn02, fv[j][1]));
			chkmin(g[i + j][1], fu[i][1] + fv[j][0]);
			chkmin(g[i + j + 1][2], fu[i][1] + fv[j][2]);
			chkmin(g[i + j + 1][2], fu[i][2] + fv[j][1]);
			chkmin(g[i + j + 2][2], fu[i][1] + fv[j][1]);
			chkmin(g[i + j][2], fu[i][2] + mn02);
		}
	for (int i = 0; i <= n + m; ++i)
		for (int p = 0; p < 3; ++p)
			fu[i][p] = g[i][p];
	n += m;
}

bool vis[MN];
int siz[MN];
LL f[MN][MN][3];
void DFS(int u, int p) {
	vis[u] = true;
	LL (*fu)[3] = f[u];
	siz[u] = 1;
	fu[0][0] = 0;
	fu[0][1] = D[u];
	fu[0][2] = fu[1][0] = fu[1][1] = fu[1][2] = Inf;
	for (int v : G[u]) if (v != p) {
		DFS(v, u);
		Merge(fu, siz[u], f[v], siz[v]);
	}
}

void Solve() {
	scanf("%d%d", &N, &M);
	for (int i = 1; i <= N; ++i) {
		scanf("%d", &D[i]);
		G[i].clear();
		vis[i] = false;
	}
	for (int i = 1; i <= M; ++i) {
		int x, y;
		scanf("%d%d", &x, &y);
		G[x].push_back(y);
		G[y].push_back(x);
	}
	static LL ans[MN];
	ans[0] = 0;
	for (int i = 1; i <= N; ++i) ans[i] = Inf;
	for (int i = 1; i <= N; ++i) if (!vis[i]) {
		DFS(i, 0);
		static LL tmp[MN];
		tmp[siz[i] + 1] = Inf;
		for (int k = siz[i]; k >= 0; --k)
			tmp[k] = std::min({f[i][k][0], f[i][k][1], f[i][k][2], tmp[k + 1]});
		for (int j = N; j >= 0; --j)
			for (int k = 0; k <= siz[i] && k <= j; ++k)
				chkmin(ans[j], ans[j - k] + tmp[k]);
	}
	int Q;
	scanf("%d", &Q);
	for (int q = 1; q <= Q; ++q) {
		int x;
		scanf("%d", &x);
		printf("%d%c", (int)(std::upper_bound(ans, ans + N + 1, x) - ans - 1), " \n"[q == Q]);
	}
}

int main() {
	int Tests;
	scanf("%d", &Tests);
	while (Tests--)
		Solve();
	return 0;
}
```

