	return a;
}
i64 gInv(i64 a) {
	i64 x = 1;
	x *= 2 - a * x;
	x *= 2 - a * x;
	x *= 2 - a * x;
	x *= 2 - a * x;
	x *= 2 - a * x;
	x *= 2 - a * x;
	return x;
}

int ctz(i64 a) {
	// deBruijn
	static const int table[64] = {
		0, 1, 2, 7, 3, 13, 8, 19,
		4, 25, 14, 28, 9, 34, 20, 40,
		5, 17, 26, 38, 15, 46, 29, 48,
		10, 31, 35, 54, 21, 50, 41, 57,
		63, 6, 12, 18, 24, 27, 33, 39,
		16, 37, 45, 47, 30, 53, 49, 56,
		62, 11, 23, 32, 36, 44, 52, 55,
		61, 22, 43, 51, 60, 42, 59, 58
	};
	static const i64 magic = 0x218A392CD3D5DBF;
	return table[((a & -a) * magic) >> 58];
}
struct mul {
	i64 v;
	int c;
	mul(i64 x) : v(x), c(0) {}
	operator i64() {
		if (c < 0 || c >= 64)
			return 0llu;
		return v << c;
	}
	mul &operator *= (i64 x) {
		int j = ctz(x);
		v *= x >> j;
		c += j;
		return *this;
	}
	mul &operator /= (i64 x) {
		int j = ctz(x);
		v *= gInv(x >> j);
		c -= j;
		return *this;
	}
};
mul Binom(i64 n, int m) {
	mul v(1);
	for (int i = 0; i < m; ++i)
		(v *= n - i) /= i + 1;
	return v;
}

const int MK = 250005;

int K;
i64 N, M, B[MK];

void Solve() {
	scanf("%d%llu%llu", &K, &N, &M), N -= K;
	for (int i = 1; i <= K; ++i) scanf("%llu", &B[i]);
	if (M == 1)
		return puts(N ? "0" : "1"), void();
	int c1 = 2, c2 = 0;
	for (int i = 2; i <= K; ++i)
		++(B[i] == B[i - 1] ? c1 : c2);
	i64 b1 = M - 1, b2 = M - 2;
	if (!c2) {
		printf("%llu\n", qPow(b1, N) * Binom(N + c1 - 1, c1 - 1));
		return ;
	}
	--c1, --c2;
	if (b1 & 1)
		std::swap(b1, b2),
		std::swap(c1, c2);
	i64 ans = 0;
	i64 pw1 = 1, pw2 = qPow(b2, N), ib2 = gInv(b2);
	mul binom1(1), binom2 = Binom(N + c2, c2);
	for (i64 i = 0; i <= N; ++i) {
		if (!pw1) break;
		ans += pw1 * pw2 * binom1 * binom2;
		if (i < N) {
			pw1 *= b1;
			pw2 *= ib2;
			(binom1 *= i + c1 + 1) /= i + 1;
			(binom2 /= N - i + c2) *= N - i;
		}
	}
	printf("%llu\n", ans);
}

int main() {
	int Tests;
	scanf("%d", &Tests);
	while (Tests--) Solve();
	return 0;
}
```

