	int q = (ax[i] - bx[i]) * (ay[j] - by[j]) - (ax[j] - bx[j]) * (ay[i] - by[i]);
	if (q < 0) px *= -1, py *= -1, q *= -1;
	printf("(%lld / %d, %lld / %d)\n", px, q, py, q);
	printf("(%.8f, %.8f)\n", px / (double)q, py / (double)q);
}
