那么接下来10分怎么办呢？

既然要求从上向下的第一个交点

就用一条线从上向下扫

按照斜率的绝对值从大到小排序，或者把坐标x，y转置一下从小向大排序

```cpp
#include <cstdio>
#include <algorithm>
#include <limits>

typedef long long LL;
const int MN = 50005;

int N;
int ax[MN], ay[MN], bx[MN], by[MN], per[MN];

double Intersect(int i, int j) {
	LL p = (LL)(ax[i] * by[i] - ay[i] * bx[i]) * (ay[j] - by[j]) - (LL)(ax[j] * by[j] - ay[j] * bx[j]) * (ay[i] - by[i]);
	int q = (ax[i] - bx[i]) * (ay[j] - by[j]) - (ax[j] - bx[j]) * (ay[i] - by[i]);
	return (double)p / q;
}

bool cmp(int i, int j) {
	return (bx[i] - ax[i]) * (by[j] - ay[j]) < (bx[j] - ax[j]) * (by[i] - ay[i]);
}

int main() {
	scanf("%d", &N);
	for (int i = 1; i <= N; ++i) {
		scanf("%d%d%d%d", &ax[i], &ay[i], &bx[i], &by[i]);
		if (ay[i] > by[i])
			std::swap(ax[i], bx[i]),
			std::swap(ay[i], by[i]);
		per[i] = i;
	}
	std::sort(per + 1, per + N + 1, cmp);
	double Ans = std::numeric_limits<double>::lowest();
	for (int i = 2; i <= N; ++i)
		Ans = std::max(Ans, Intersect(per[i - 1], per[i]));
	printf("%.8f\n", Ans);
	return 0;
}
```

