### 思路

也就是说我们要从a个数中选出k个数乘起来

```cpp
#include <cstdio>

typedef long long LL;
const int Mod = 998244353;
const int MK = 305;

int qPow(int b, int e) {
	int a = 1;
	for (; e; e >>= 1, b = (LL)b * b % Mod)
		if (e & 1) a = (LL)a * b % Mod;
	return a;
}

int N, K;
int f[MK], g[MK];

int main() {
	scanf("%d%d", &N, &K);
	f[0] = g[0] = 1;
	for (int i = 1; i <= N; ++i) {
		int x;
		scanf("%d", &x);
		for (int j = 1; j <= K; ++j) {
			f[j] = (f[j] + f[j - 1]) % Mod;
			g[j] = (g[j] + (LL)x * g[j - 1]) % Mod;
		}
	}
	printf("%lld\n", (LL)g[K] * qPow(f[K], Mod - 2) % Mod);
	return 0;
}
```

