Matrix operator * (const Matrix &p, const Matrix &q) {
	Matrix res;
	for (int i = 0; i < 4; ++i)
		for (int k = 0; k < 4; ++k)
			for (int j = 0; j < 4; ++j)
				res.A[i][j] = (res.A[i][j] + (LL)p.A[i][k] * q.A[k][j]) % Mod;
	return res;
}
Matrix qPow(Matrix b, LL e) {
	Matrix a(1);
	for (; e; e >>= 1, b = b * b)
		if (e & 1) a = a * b;
	return a;
}
const int Arr[4][4] = {
	{1, 2, 0, 2},
	{1, 3, 2, 2},
	{3, 8, 5, 6},
	{1, 2, 1, 2}
};

int main() {
	int Tests;
	scanf("%d", &Tests);
	while (Tests--) {
		scanf("%lld", &N);
		Matrix A;
		for (int i = 0; i < 4; ++i)
			for (int j = 0; j < 4; ++j)
				A.A[i][j] = Arr[i][j];
		A = qPow(A, N / 5);
		int Ans = (A.A[0][0] + A.A[0][1] + 3ll * A.A[0][2] + A.A[0][3]) % Mod;
		printf("%d\n", Ans);
	}
	return 0;
}
