### 思路

##### 算法1

随便数一数，然后枚举一哈~，大概能过20%的数据吧?qaq

期望得分20分？

##### 算法2

对于每一对$(i,j)$,的gcd直接调用系统函数，然后直接对着每一条线用组合数计算

为什么使用组合数呢，我们可以先固定两个，然后对于后面的，直接变成几选几的问题了，一直往后推也非常好理解

期望得分90分

##### 算法3

限制了算法2的想象的主要是gcd的调用太慢了，所以运用@Hazyknight的话，我们可以直接进行递推就可以把一堆gcd给算出来了，即：
$
g[i][j]=(i>j?) g[i-1][j]:g[i][j-1];
$

时间复杂度$O(n^2)$

期望得分100分

##### 算法4

但是Hazyknight还有更nb的算法，但是我们已经得到一百分了，那就来欣赏一下

其实本题可以只用$O(n)$的空间。甚至不需要存储整个棋盘！

考虑平面$0<=i<=n ,  0<=j<=n$且i,j互质的数对在平面上的射线。

假设相邻两条射线的是(a,b) (c,d)那么一定满足$|ad-bc|=1。$

于是我们直接从(0,1)开始旋转枚举射线，和射线上的点然后预处理$A^n$快速计算对应格子是0还是1即可。

### 代码

std

```cpp
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;

const int MAXN = 5005;
const ll MOD = 998244353;

int n,m,K;
int v[MAXN][MAXN];
int g[MAXN][MAXN];

ll A,b,x0,p,l,ans;
ll f[MAXN];
ll fac[MAXN];
ll inv[MAXN];

ll power(ll a,ll b)
{
	ll res = 1;
	while (b)
	{
		if (b & 1)
			(res *= a) %= MOD;
		(a *= a) %= MOD;
		b >>= 1;
	}
	return res;
}

ll C(int x,int y)
{
	return x < y ? 0 : fac[x] * inv[y] % MOD * inv[x - y] % MOD;
}

void init()
{
	int N = max(n + 1,m + 1);
	fac[0] = 1;
	for (int i = 1;i <= N;i++)
		fac[i] = fac[i - 1] * i % MOD;
	inv[N] = power(fac[N],MOD - 2);
	for (int i = N;i >= 1;i--)
		inv[i - 1] = inv[i] * i % MOD;
	for (int i = 1;i <= N;i++)
		f[i] = C(i,K);
}

int main()
{
	freopen("connectk.in","r",stdin);
	freopen("connectk.out","w",stdout);
	cin >> n >> m >> K >> A >> x0 >> b >> p >> l;
	n--,m--;
	init();
	for (int i = 0;i <= n;i++)
		for (int j = 0;j <= m;j++)
		{
			x0 = (A * x0 + b) % p;
			v[i][j] = (x0 <= l);
		}
	if (K == 1)
	{
		for (int i = 0;i <= n;i++)
			for (int j = 0;j <= m;j++)
				(ans += v[i][j]) %= MOD;
		cout << ans << endl;
		return 0;
	}
	for (int i = 0;i <= n;i++)
		for (int j = 0;j <= m;j++)
			if (!i || !j)
				g[i][j] = i | j;
			else
				g[i][j] = (i > j ? g[i - j][j] : g[i][j - i]);
	for (int i = n;i >= 0;i--)
		for (int j = m;j >= 0;j--)
			if ((i || j) && g[i][j] != 1)
			{
				v[i / g[i][j]][j / g[i][j]] += v[i][j];
				v[i][j] = 0;
			}
	for (int i = 0;i <= n;i++)
		for (int j = 0;j <= m;j++)
			if (g[i][j] == 1)
				(ans += f[v[i][j] + v[0][0]]) %= MOD;
	cout << ans << endl;
	return 0;
}
```

