### 思路

##### 算法1

实际上就没有思路，直接大爆搜，枚举每个集合，再判断是不是城市群

期望得分20分

##### 算法2

考虑城市群S到底是啥。

若u,v两个点在同一个点双连通分量中且全部属于S，则这个点双连通分量的所有点也一定都属于S。那么我们构建出原图的圆方树。一个合法的城市群一定是圆方树上一个全部在圆点与外界交接的连通块，直接对于每一次询问进行一次树形DP即可。

时间复杂度$O(nq)$

期望得分44。

##### 算法3

对于一条链和一棵树，大概可以通过一些结论DP出解。

能得到额外的8、12分。

期望得分64分

##### 算法4

我们只需要求出对于每个点i，有多少个包含i的城市群即可。

我们采用两次dfs即可，第一次dfs计算fi表示i的子树和i有多少种可行的城市群方案，第二次计算gi表示i和i的父亲有多少种可行的城市群方案。gi用fi来更新即可（可能需要一个前缀后缀乘积）。

复杂度$O(n+q)$。

期望得分100分

### 代码

std

```cpp
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;

inline char gc()
{
	static char buf[524288],*p1 = buf,*p2 = buf;
	return p1 == p2 && (p2 = (p1 = buf) + fread(buf,1,524288,stdin),p1 == p2) ? EOF : *p1++;
}

inline void read(int &v)
{
	v = 0;
	char c = gc();
	while (c < '0' || c > '9')
		c = gc();
	while (c >= '0' && c <= '9')
	{
		v = v * 10 + c - '0';
		c = gc();
	}
}

const int MAXN = 2000005;
const ll MOD = 998244353;

struct Edge
{
	int to;
	int nxt;
}edge[MAXN << 1];

int n,m,q,id,cc,ee,tot;
int w[MAXN];
int first[MAXN];
int dfn[MAXN];
int low[MAXN];
int bel[MAXN];
int U[MAXN];
int V[MAXN];

bool vis[MAXN];

ll f[MAXN];
ll g[MAXN];
ll pre[MAXN];
ll suf[MAXN];

stack<int> S;

void addE(int u,int v)
{
	edge[++id] = (Edge){v,first[u]};
	first[u] = id;
}

void tarjan(int u,int fa)
{
	dfn[u] = low[u] = ++id;
	vis[u] = 1;
	S.push(u);
	for (int i = first[u];i;i = edge[i].nxt)
		if (edge[i].to != fa)
		{
			int to = edge[i].to;
			if (!dfn[to])
			{
				tarjan(to,u);
				low[u] = min(low[u],low[to]);
				if (low[to] >= dfn[u])
				{
					cc++;
					ee++;
					U[ee] = u;
					V[ee] = cc + n;
					while (S.top() != to)
					{
						vis[S.top()] = 0;
						ee++;
						U[ee] = cc + n;
						V[ee] = S.top();
						S.pop();
					}
					vis[S.top()] = 0;
					ee++;
					U[ee] = cc + n;
					V[ee] = S.top();
					S.pop();
				}
			}
			else if (vis[to])
				low[u] = min(low[u],dfn[to]);
		}
}

void dfs1(int u)
{
	f[u] = 1;
	for (int i = first[u];i;i = edge[i].nxt)
	{
		dfs1(edge[i].to);
		(f[u] *= f[edge[i].to] + (u <= n)) %= MOD;
	}
}

void dfs2(int u)
{
	pre[0] = 1;
	int j = 1;
	for (int i = first[u];i;i = edge[i].nxt,j++)
	{
		pre[j] = pre[j - 1] * (f[edge[i].to] + (u <= n)) % MOD;
		S.push(i);
	}
	suf[j] = 1;
	while (!S.empty())
	{
		j--;
		int i = S.top();
		suf[j] = suf[j + 1] * (f[edge[i].to] + (u <= n)) % MOD;
		S.pop();
	}
	j = 1;
	for (int i = first[u];i;i = edge[i].nxt,j++)
		g[edge[i].to] = g[u] * pre[j - 1] % MOD * suf[j + 1] % MOD + (edge[i].to <= n);
	for (int i = first[u];i;i = edge[i].nxt)
	{
		(g[u] *= f[edge[i].to] + (u <= n)) %= MOD;
		dfs2(edge[i].to);
	}
}

int main()
{
	freopen("federation.in","r",stdin);
	freopen("federation.out","w",stdout);
	read(n),read(m);
	for (int i = 1;i <= n;i++)
		read(w[i]);
	for (int u,v,i = 1;i <= m;i++)
	{
		read(u),read(v);
		addE(u,v);
		addE(v,u);
	}
	id = 0;
	tarjan(1,0);
	id = 0;
	memset(first,0,sizeof(first));
	for (int i = 1;i <= ee;i++)
		addE(U[i],V[i]);
	dfs1(1);
	g[1] = 1;
	dfs2(1);
	ll ans = 0;
	for (int i = 1;i <= n;i++)
		(ans += g[i] * w[i]) %= MOD;
	read(q);
	while (q--)
	{
		int x,y;
		read(x),read(y);
		(ans += g[x] * (y - w[x])) %= MOD;
		w[x] = y;
		printf("%lld\n",(ans + MOD) % MOD);
	}
	return 0;
}

```

## T3 能源供应

#### 题目描述

一座城市主要由两种方式供应能源，火力发电和风力发电。其中，火电每次开启需要$C$的代价，持续运行时每一天并且产生$x$度电的代价是$max(D,kx)$（因为就算不发电也需要维持开机状态，消耗至少为$D$）。而风力发电在特定一天发$x$度电的代价为$v_ix$（风力大小等因素会导致$v_i$每一天可能不同），同时由于天气原因可能存在若干天并不能发电。两种方式都可以选择在任何时间开关以及每天发任意度的点。现在给出这座城市$n$天的电力需求，求一个代价最小的满足电力需求的发电方案。

不过，火电站由于不受外界影响，预测相对准确；风力发电需要对天气的预告，具有不确定性。所以现在要求有$q$次修改，每次修改修改一天的$v_i$，每次修改后询问一次最小代价。**注意，以上过程中任何电站只能发整数单位的电**。

#### 输入格式

从文件$\texttt{energy.in}$中读取数据。

第一行四个整数$n,C,D,k$。

第二行$n$个整数$v_i$，表示第$i$天风力发一度电的代价。

第三行$n$个整数$a_i$,表示每天需要的电量（度）。

第四行一个整数$q$。

接下来$q$行，每行两个整数$x,y$，表示将$v_x$修改为$y$。

