### 思路

##### 算法1

直接枚举每一天是否开启火电站，和每天火电站发多少电，然而时间复杂度很大qaq

期望得分10分

##### 算法2

可以发现，每天开不开火电站发电量是一定的，也就是说最优解是一定的

所以我们只关心每一天开不开火电站，直接枚举就好了

时间复杂度$O(2^nnq)$

期望得分25分

##### 算法3

实际上我们从最优解的角度来想，很容易就能想到这道题需要使用的算法为动态规划

对算法2进行DP优化，令$f[i][0/1]$表示前i天，最后一天是否开启火电站的最小花费，转移时候直接尝试下一天是否开火电站即可，每一次单独DP。

时间复杂度$O(nq)$

期望得分60分

##### 算法4

然而这样的DP并不能达到我们题目的要求，所以我们要进行DP优化

算法3中的DP可以优化。

考虑转移形式大概是视(fi0,fi1)为一个向量，用min代替+，用+代替*做一次矩阵乘法。

类似$f[i+1][0]=min(f[i][0]+?,f[i][1]+?)$

可以发现min，+是floyd矩阵，满足结合律。

由于每一次只修改一天的代价，故用线段树维护矩阵连乘积。

复杂度$O(qlogn)$。

期望得分100分

### 代码

std

```cpp
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;

const int MAXN = 200005;

struct Matrix
{
	ll a[2][2];

	Matrix()
	{
		memset(a,0,sizeof(a));
	}

	Matrix operator * (const Matrix &p)const
	{
		Matrix res;
		res.a[0][0] = min(a[0][0] + p.a[0][0],a[0][1] + p.a[1][0]);
		res.a[0][1] = min(a[0][0] + p.a[0][1],a[0][1] + p.a[1][1]);
		res.a[1][0] = min(a[1][0] + p.a[0][0],a[1][1] + p.a[1][0]);
		res.a[1][1] = min(a[1][0] + p.a[0][1],a[1][1] + p.a[1][1]);
		return res;
	}
}M[MAXN << 2];

int n,q;

ll C,D,k;
ll v[MAXN];
ll a[MAXN];
ll c0[MAXN];
ll c1[MAXN];

void buildtree(int o,int l,int r)
{
	if (l == r)
	{
		M[o].a[0][0] = M[o].a[1][0] = c0[l];
		M[o].a[0][1] = C + c1[l];
		M[o].a[1][1] = c1[l];
		return;
	}
	int mid = l + r >> 1;
	buildtree(o << 1,l,mid);
	buildtree(o << 1 | 1,mid + 1,r);
	M[o] = M[o << 1] * M[o << 1 | 1];
}

void modify(int o,int l,int r,int p)
{
	if (l == r)
	{
		M[o].a[0][0] = M[o].a[1][0] = c0[l];
		M[o].a[0][1] = C + c1[l];
		M[o].a[1][1] = c1[l];
		return;
	}
	int mid = l + r >> 1;
	if (mid >= p)
		modify(o << 1,l,mid,p);
	else
		modify(o << 1 | 1,mid + 1,r,p);
	M[o] = M[o << 1] * M[o << 1 | 1];
}

int main()
{
	freopen("energy.in","r",stdin);
	freopen("energy.out","w",stdout);
	scanf("%d%lld%lld%lld",&n,&C,&D,&k);
	for (int i = 1;i <= n;i++)
		scanf("%lld",&v[i]);
	for (int i = 1;i <= n;i++)
	{
		scanf("%lld",&a[i]);
		c0[i] = v[i] * a[i];
		c1[i] = min(min(D + max(0ll,a[i] - D / k) * v[i],(D / k + 1) * k + max(0ll,a[i] - D / k - 1) * v[i]),max(D,k * a[i]));
	}
	buildtree(1,1,n);
	scanf("%d",&q);
	bool ok = 0;
	while (q--)
	{
		int x;
		ll y;
		scanf("%d%lld",&x,&y);
		v[x] = y;
		c0[x] = v[x] * a[x];
		c1[x] = min(min(D + max(0ll,a[x] - D / k) * v[x],(D / k + 1) * k + max(0ll,a[x] - D / k - 1) * v[x]),max(D,k * a[x]));
		modify(1,1,n,x);
		printf("%lld\n",min(M[1].a[0][0],M[1].a[0][1]));
	}
	return 0;
}

```

