##### 算法4

上面的算法和一个部分分“合法区间不超过…”提示我们是不是可以维护极少的合法区间即可。

事实上，如果一个区间[l,r]满足l>1且a{l-1}比[l,r]内的a最大值要小，那么[l-1,r]答案一定不比[l,r]差。所以只需考虑两侧都比区间内所有数大的区间，这样的区间至多有n个，称他们为极大区间。

考虑建立一棵树，树根是a最大的节点，接下来往两侧递归建树。

这样一颗树的一个子树就是一个极大区间。

接下来问题变成，树上一个点到根加一个值，询问最小的满足值>=V的点。直接倍增+树状数组维护即可。

时间复杂度$O((n+q)logn)$。

期望得分100。

### 代码

std

```cpp
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;

const int MAXN = 300005;

int n,q,ans,top;
int S[MAXN];
int a[MAXN];
int b[MAXN];
int l[MAXN];
int r[MAXN];
int pos[MAXN];
int fa[MAXN][20];

bool vis[MAXN];

ll V;
ll sum[MAXN];

void modify(int p,int x)
{
	while (p <= n)
	{
		sum[p] += x;
		p += p & -p;
	}
}

ll query(int p)
{
	ll res = 0;
	while (p >= 1)
	{
		res += sum[p];
		p -= p & -p;
	}
	return res;
}

int main()
{
	freopen("sequence.in","r",stdin);
	freopen("sequence.out","w",stdout);
	scanf("%d%lld",&n,&V);
	for (int i = 1;i <= n;i++)
	{
		scanf("%d",&a[i]);
		pos[a[i]] = i;
	}
	for (int i = 1;i <= n;i++)
	{
		scanf("%d",&b[i]);
		modify(i,b[i]);
	}
	a[0] = a[n + 1] = 1e9;
	S[++top] = 0;
	for (int i = 1;i <= n;i++)
	{
		while (a[S[top]] < a[i])
			top--;
		l[i] = S[top];
		S[++top] = i;
	}
	S[top = 1] = n + 1;
	for (int i = n;i >= 1;i--)
	{
		while (a[S[top]] < a[i])
			top--;
		r[i] = S[top];
		S[++top] = i;
	}
	for (int i = 1;i <= n;i++)
	{
		fa[i][0] = (a[l[i]] < a[r[i]] ? l[i] : r[i]);
		if (a[i] == n)
			fa[i][0] = 0;
	}
	for (int i = n;i >= 1;i--)
	{
		int u = pos[i];
		for (int j = 1;j <= 18;j++)
			fa[u][j] = fa[fa[u][j - 1]][j - 1];
	}
	ans = 1e9;
	for (int i = 1;i <= n;i++)
		if (query(r[i] - 1) - query(l[i]) >= V)
		{
			vis[i] = 1;
			ans = min(ans,a[i]);
		}
	scanf("%d",&q);
	while (q--)
	{
		int x,y;
		scanf("%d%d",&x,&y);
		modify(x,y);
		int u;
		if (!vis[x])
		{
			do
			{
				u = x;
				for (int j = 18;j >= 0;j--)
					if (fa[u][j] && !vis[fa[u][j]])
						u = fa[u][j];
				if (query(r[u] - 1) - query(l[u]) >= V)
				{
					vis[u] = 1;
					ans = min(ans,a[u]);
				}
			}while (u != x && vis[u]);
		}
		printf("%d\n",ans == 1e9 ? -1 : ans);
	}
	return 0;
}

```

