### 最终代码

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=100010;
int n,m,p;
int a[maxn];
struct tree{
	int l,r;
	long long dat,add,mul;
}t[maxn*4+5];
void pushup(int k)
{
	t[k].dat=(t[k<<1].dat+t[k<<1|1].dat)%p;
}
void pushdown(int k)
{
	//传递节点 
	t[k<<1].dat=(t[k<<1].dat*t[k].mul+t[k].add*(t[k<<1].r-t[k<<1].l+1))%p;
	t[k<<1|1].dat=(t[k<<1|1].dat*t[k].mul+t[k].add*(t[k<<1|1].r-t[k<<1|1].l+1))%p;
	//传递乘法的懒惰标记 
	t[k<<1].mul=(t[k].mul*t[k<<1].mul)%p;
	t[k<<1|1].mul=(t[k].mul*t[k<<1|1].mul)%p;
	//传递加法的懒惰标记 
	t[k<<1].add=(t[k<<1].add*t[k].mul+t[k].add)%p;
	t[k<<1|1].add=(t[k<<1|1].add*t[k].mul+t[k].add)%p;
	//还原父节点，因为子节点已经更新过了 
	t[k].add=0;
	t[k].mul=1;
}
//k代表当前节点，l代表当前节点的左端点，r代表当前节点的右端点 
void build(int k,int l,int r)
{
	//储存一下左端点和右端点，方便以后调用
	//同时做一下延迟标记的初始化 
	t[k].l=l,t[k].r=r;
	t[k].add=0,t[k].mul=1;
	if(l==r)
	{
		t[k].dat=a[l];//如果到区间长度为1的时候，那么这个时候就等于对应的数字 
		return ;
	}
	int mid=(l+r)>>1;
	build(k<<1,l,mid);//递归建左子树 
	build(k<<1|1,mid+1,r);//递归建右子树 
	pushup(k);//向父节点输送左子树和右子树的数据 
	t[k].dat%=p;
	return ;
}
void updata1(int k,int l,int r,int v)
{
	if(l<=t[k].l&&r>=t[k].r)
	{
		t[k].dat=(t[k].dat*v)%p;
		t[k].mul=(t[k].mul*v)%p;
		return ;
	}
	pushdown(k);
	int mid=(l+r)>>1;
	if(l<=mid)
	updata1(k<<1,l,r,v);
	if(r>mid)
	updata1(k<<1|1,l,r,v);
	pushup(k);
}
void updata2(int k,int l,int r,int v)
{
	if(l<=t[k].l&&r>=t[k].r)
	{
		t[k].dat=(t[k].dat+v*(t[k].r-t[k].l+1))%p;
		t[k].mul=(t[k].add+v)%p;
		return ;
	}
	pushdown(k);
	int mid=(l+r)>>1;
	if(l<=mid)
	updata2(k<<1,l,r,v);
	if(r>mid)
	updata2(k<<1|1,l,r,v);
	pushup(k);
}
long long query(int k,int l,int r)
{
	if(l<=t[k].r&&r>=t[k].r)
	return t[k].dat;
