int main()
{
	//freopen("cake.in","r",stdin);
	//freopen("cake.out","w",stdout);
	cin>>T;
	while(T--)
	{
		int a,b,c;
		cin>>a>>b>>c;
		if(a==0&&b==0||b==0&&c==0||a==0&&c==0)
		cout<<0<<endl;
		else if(a==0)
		{
			if(b==c)
			cout<<1<<endl;
			else
			cout<<2<<endl;
		}
		else if(b==0)
		{
			if(a==c)
			cout<<1<<endl;
			else
			cout<<2<<endl; 
		}
		else if(c==0)
		{
			if(a==b)
			cout<<1<<endl;
			else
			cout<<2<<endl;
		}
		else if(a+b==c||a+c==b||b+c==a)
		{
			cout<<2<<endl;
		}
		else if(a==b||a==c||b==c)
		{
			cout<<2<<endl;
		}
		else
		{
			cout<<3<<endl;
		}
	}
	//fclose(stdin);
