12223331111

### 【数据规模与约定】

20% n<=5 m=0 k=2

30% n<=10 m<=10 k<=5

40% n<=17 m<=20 k<=5

50% n<=18 m<=20 k<=5

60% n<=19 m<=20 k<=5

70% n<=20 m<=20 k<=5

100% n<=20 m<=10000 k<=8

## 思路

看成不断添加一个新数字

这样相当于好数组成一个哈密顿通路

只需要求出两两好数之间最短距离，然后状压dp求出哈密顿通路

好数之间距离可以使用最短路算法求出，数据范围较小时可能有些其他的求法

由于边权均为1~4，可以拆边使用bfs求最短路，直接最短路可能会被卡时间

8位1-4组成的数可以看作4进制数进行运算，从而节省空间

## 代码

```cpp
#include<queue>
#include<cstdio>
#include<cstring>
#include<algorithm>
#define N 100010
#define pa pair<int,int>
using namespace std;
int n,m,k;
int good[25],bad[10005];
int dis[N][4];
bool vis[N];
int trans(int x)
{
	int y=0;
	for(int i=0;i<k;i++)
	{
		y|=(x%10-1)<<(2*i);
		x/=10;
	}
	return y;
}
queue<pa>q;
void bfs(int x)
{
	memset(dis,0x3f,sizeof(dis));
	if(vis[x])return;
	dis[x][0]=0;
	q.push(pa(x,0));
	while(!q.empty())
	{
		pa x=q.front();
		q.pop();
		int now=dis[x.first][x.second];
		if(x.second)
		{
			if(dis[x.first][x.second-1]>1e9)
			{
				dis[x.first][x.second-1]=now+1;
				q.push(pa(x.first,x.second-1));
			}
			continue;
		}
		for(int i=1;i<=4;i++)
		{
			int y=((x.first<<2)|(i-1))&((1<<(2*k))-1);
			if(dis[y][i-1]>1e9&&!vis[y])
			{
				dis[y][i-1]=now+1;
				q.push(pa(y,i-1));
			}
		}
	}
}
int dist[25][25];
int f[21][1<<20];
int calc(int x)
{
	int y=0;
	for(int i=0;i<k;i++)
	{
		y+=x%10;
		x/=10;
	}
	return y;
}
int main()
{
//	freopen("num8.in","r",stdin);
//	freopen("num2.out","w",stdout);
	scanf("%d%d%d",&n,&m,&k);
	for(int i=1;i<=n;i++)
		scanf("%d",&good[i]);
	for(int i=1;i<=m;i++)
	{
		scanf("%d",&bad[i]);
		vis[trans(bad[i])]=1;
	}
	for(int i=1;i<=n;i++)
	{
		bfs(trans(good[i]));
		for(int j=1;j<=n;j++)
			dist[i][j]=dis[trans(good[j])][0];
	}
	memset(f,0x3f,sizeof(f));
	for(int i=1;i<=n;i++)
		f[i][1<<(i-1)]=calc(good[i]);
	for(int S=0;S<(1<<n);S++)
	for(int i=1;i<=n;i++)
	if((S&(1<<(i-1))))
	{
		for(int j=1;j<=n;j++)
		if(!(S&(1<<(j-1))))
		f[j][S|(1<<(j-1))]=min(f[j][S|(1<<(j-1))],f[i][S]+dist[i][j]);
	}
/*	int I[25],ii,J[25],jj;
	for(int S=1;S<(1<<n);S++)
	{
		ii=jj=0;
		for(int i=1;i<=n;i++)
			if((S>>(i-1))&1)
			{
				if(f[i][S]<1e9)
					I[++ii]=i;
			}
			else
				J[++jj]=i;
		for(int i=1;i<=ii;i++)
		{
			int iii=I[i];
			for(int j=1;j<=jj;j++)
				f[J[j]][S|(1<<(J[j]-1))]=min(f[J[j]][S|(1<<(J[j]-1))],
					f[iii][S]+dist[iii][J[j]]);
		}	
	}*/
	int ans=1e9;
	for(int i=1;i<=n;i++)
		ans=min(ans,f[i][(1<<n)-1]);
	printf("%d\n",ans);
