时间限制：1s

空间限制：512MB

## 思路

~~这个真的不会~~

引用qbxt：

可以发现三个点是“组合”当且仅当与中间点距离为2且互相在中间点的不同子树中

一次树形dp求出每个点子节点的权的和f

对于一个中间点，它的贡献就是每个子节点（包括父亲）的f值集合中任取3个的乘积的和

## 代码

```cpp
#include<iostream>
#include<cstdio>
#include<cstring>
#include<algorithm>
#define dd double
#define ll long long
#define N 1000010
#define M 1010
using namespace std;
int n,u,v,a[N];
int s,to[N*2],ne[N*2],pre[N];
int fa[N],f[N];
ll ans;
void add(int u,int v)
{
	to[++s]=v;
	ne[s]=pre[u];
	pre[u]=s;
}
void dfs(int k)
{
	for(int i=pre[k];i;i=ne[i])
	if(to[i]!=fa[k])
	{
		int x=to[i];
		fa[x]=k;
		dfs(x);
		f[k]+=a[x];
	}
}
int main()
{
	//freopen("./match/match1.in","r",stdin);
	//freopen("./match/match1.out","w",stdout);

	cin>>n;
	for(int i=1;i<=n;i++) scanf("%d",&a[i]);
	for(int i=1;i<n;i++)
	{
		scanf("%d%d",&u,&v);
		add(u,v);
		add(v,u);
	}
	dfs(1);
	for(int i=1;i<=n;i++)
	{
		ll s1=a[fa[fa[i]]];
		if(i>1) s1+=f[fa[i]]-a[i];
		ll s2=0; 
		for(int j=pre[i];j;j=ne[j])
		if(to[j]!=fa[i])
		{
			int x=to[j];
			ans+=s2*f[x];
			s2+=s1*f[x];
			s1+=f[x];
		}
	}
	cout<<ans<<endl;
    return 0;
}
```

