//动态规划
#include<cstdio>
#include<cstdlib>
#include<cstring>
#include<algorithm>
using namespace std;
const int maxn=210;
int n,m,z[maxn],f[maxn][maxn];
int main()
{
	freopen("in","r",stdin);
	freopen("out","w",stdout);
	scanf("%d%d",&n,&m);
	for (int a=1;a<=n;a++)
		scanf("%d",&z[a]);
	sort(z+1,z+n+1);
	memset(f,0x3f,sizeof(f));
	for (int a=1;a<=n;a++)
		f[a][a]=z[a];
	for (int len=2;len<=n;len++)
	for (int l=1,r=len;r<=n;l++,r++)
	for (int k=l;k<r;k++)
	f[l][r] = min(f[l][r], max(f[l][k],f[k+1][r])+m);
	printf("%d\n",f[1][n]);
	return 0;
}
