#define wmt 1,n,1
#define lson l,m,rt<<1
#define rson m+1,r,rt<<1|1
const int maxn=100010;
const int mo=1000000007;
int n,m,k,invm;
int mul(int a,int b)
{
	int ans=1;
	while (b)
	{
		if (b&1) ans=1ll*ans*a%mo;
		a=1ll*a*a%mo;
		b>>=1;
	}
	return ans;
}
struct node
{
	int l_to_r,r_to_l;
	int prob_decay;

	int col;
	int lr_prob,rl_prob;

	void init(int v,int a,int b)
	{
		int p = 1ll*a*mul(b,mo-2)%mo;
		l_to_r = r_to_l = 1ll*v*p%mo;
		prob_decay = (1-1ll*p*invm%mo+mo)%mo;

		col = 0;
		lr_prob = rl_prob = p;
	}
}z[maxn<<2];
node operator+(const node &l,const node &r)
{
	node p;
	p.l_to_r = ( 1ll * l.l_to_r * r.prob_decay + r.l_to_r) % mo;
	p.r_to_l = ( 1ll * r.r_to_l * l.prob_decay + l.r_to_l) % mo;
	p.prob_decay = 1ll*l.prob_decay*r.prob_decay % mo;

	p.col = 0;
	p.lr_prob = (1ll * l.lr_prob * r.prob_decay + r.lr_prob)%mo;
	p.rl_prob = (1ll * r.rl_prob * l.prob_decay + l.rl_prob)%mo;

	return p;
}
node color(node p,int v)
{
	p.col = (p.col + v)%mo;
	p.l_to_r = (p.l_to_r + 1ll * p.lr_prob * v)%mo;
	p.r_to_l = (p.r_to_l + 1ll * p.rl_prob * v)%mo;

	return p;
}
void update(int rt)
{
	z[rt] = z[rt<<1] + z[rt<<1|1];
}

void push_col(int rt)
{
	z[rt<<1] = color(z[rt<<1],z[rt].col);
	z[rt<<1|1] = color(z[rt<<1|1],z[rt].col);
	z[rt].col=0;
}
void build(int l,int r,int rt)
{
	if (l==r)
	{
		int v,a,b;
		readint(v);
		readint(a);
		readint(b);
		z[rt].init(v,a,b);
		return;
	}
	int m=(l+r)>>1;
	build(lson);
	build(rson);
	update(rt);
}

void modify(int l,int r,int rt,int p)
{
	if (l==r)
	{
		int a,b,v;
		readint(v);
		readint(a);
		readint(b);
		z[rt].init(v,a,b);
		return;
	}
	push_col(rt);
	int m=(l+r)>>1;
	if (p<=m) modify(lson,p);
	else modify(rson,p);
	update(rt);
}
void modify(int l,int r,int rt,int nowl,int nowr,int v)
{
	if (nowl<=l && r<=nowr)
	{
		z[rt] = color(z[rt],v);
		return;
	}
	push_col(rt);
	int m=(l+r)>>1;
	if (nowl<=m) modify(lson,nowl,nowr,v);
	if (m<nowr) modify(rson,nowl,nowr,v);
	update(rt);
}

node query(int l,int r,int rt,int nowl,int nowr)
{
	if (nowl<=l && r<=nowr) return z[rt];
	int m=(l+r)>>1;
	push_col(rt);
	if (nowl<=m)
	{
		if (m<nowr) return query(lson,nowl,nowr)+query(rson,nowl,nowr);
		else return query(lson,nowl,nowr);
	}
	else return query(rson,nowl,nowr);
}
int main()
{
	readint(n);
	readint(m);
	readint(k);
	invm = mul(m,mo-2);
	build(wmt);
	for (int a=1;a<=k;a++)
	{
		int opt;
		readint(opt);
		if (opt==1)
		{
			int p1,p2;
			readint(p1);
			readint(p2);
			if (p1<=p2) printf("%d\n",query(wmt,p1,p2).l_to_r);
			else printf("%d\n",query(wmt,p2,p1).r_to_l);
		}
		else if (opt==2)
		{
			int p;
			readint(p);
			modify(wmt,p);
		}
		else
		{
			int l,r,v;
			readint(l);
			readint(r);
			readint(v);
			modify(wmt,l,r,v);
		}
	}
	return 0;
}
