#include<cstdio>
#include<cstdlib>
#include<cstring>
#include<vector>
#include<cmath>
using namespace std;
const int maxn=100010;
struct point
{
	long long x,y;
	point(){}
	point(long long a,long long b){x=a;y=b;}
}p[maxn];
point operator+(const point &p1,const point &p2)
{
	return point(p1.x+p2.x,p1.y+p2.y);
}
point operator-(const point &p1,const point &p2)
{
	return point(p1.x-p2.x,p1.y-p2.y);
}
long long operator*(const point &p1,const point &p2)
{
	return p1.x*p2.y-p1.y*p2.x;
}
int sgn(long long a)
{
	if (a==0) return 0;
	if (a>0) return 1;
	return -1;
}
class worker {
public:
    vector <int> work(vector <int> x, vector <int> y, vector <int> d) {
        vector <int> res;
		for (int t=0;t<x.size();t++)
		{
			point q=point(abs(x[t]),abs(y[t]));
			int td=d[t];
			if (q.x==0 && q.y==0)
			{
				res.push_back(0);
				continue;
			}
			if (q.x==0 || q.y==0)
			{
				res.push_back((q.x+q.y-1)/(int(sqrt(td)))+1);
				continue;
			}
			int n=0;
			for (int a=0;a*a<=td;a++)
			{
				int b=sqrt(td-a*a);
				if (a>b) break;
				p[++n] = point(a,b);
				while (n>2 && (p[n]-p[n-2])*(p[n-1]-p[n-2]) < 0)
				{
					n--;
					p[n]=p[n+1];
				}
			}
			for (int a=n+1;a<=n+n;a++)
				p[a] = point(p[n+n+1-a].y,p[n+n+1-a].x);
			n<<=1;
			int x;
			for (int a=1;a<n;a++)
				if (sgn(q*p[a])*sgn(q*p[a+1])<=0)
				{
					x=a;
					break;
				}
			long long l=0;
			long long r=2;
			if (p[x].y) r+=q.y/p[x].y;
			if (p[x+1].x) r+=q.x/p[x+1].x;
			while (l+1!=r)
			{
				long long m=(l+r)>>1;
				point p1=p[x];
				point p2=p[x+1];
				p1.x*=m;p1.y*=m;
				p2.x*=m;p2.y*=m;
				if ((q-p1)*(p2-p1) >=0) r=m;
				else l=m;
			}
			res.push_back(int(r));
		}
        return res;
    }
};

int main()
{
	worker obj;
	vector<int> x;
	vector<int> y;
	vector<int> d;
	int a,b,c;
	while (~scanf("%d%d%d",&a,&b,&c))
	{
		x.push_back(a);
		y.push_back(b);
		d.push_back(c);
	}
	vector<int> res=obj.work(x,y,d);
	for (int a=0;a<res.size();a++)
		printf("%d\n",res[a]);
	return 0;
}

