void mergesort(int l,int r)
{
    if(l>=r) return ;
    int mid=(l+r)>>1;
    mergesort(l,mid),mergesort(mid+1,r);
    int head1=l,head2=mid+1;
    for(int i=l;i<=r;i++)
    {
        if(head2<=r &&(head1>mid||a[head2]<a[head1]))
            q[i]=a[head2++];
        else
            q[i]=a[head1++],cnt+=(head2-mid-1);
    }
    for(int i=1;i<=r;i++)
        a[i]=q[i];
    return ;
}
