#### 线段树

```cpp
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
using namespace std;
const int maxn=100010;
int a[maxn+5];
struct tree{
	int l,r;
	long long dat,lazy;
}t[maxn*4+5];
void pushup(int k)
{
	t[k].dat=t[k<<1].dat+t[k<<1|1].dat;
}
void build(int k,int l,int r)
{
	t[k].l=l,t[k].r=r;
	if(l==r)
	{
		t[k].dat=a[l];
		return ;
	}
	int mid=(l+r)>>1;
	build(k<<1,l,mid);
	build(k<<1|1,mid+1,r);
	pushup(k);
}
void pushdown(int k)
{
	if(t[k].lazy)
	{
		t[k<<1].dat+=t[k].lazy*(t[k<<1].r-t[k<<1].l+1);
		t[k<<1|1].dat+=t[k].lazy*(t[k<<1|1].r-t[k<<1|1].l+1);
		t[k<<1].lazy+=t[k].lazy;
		t[k<<1|1].lazy+=t[k].lazy;
		t[k].lazy=0;
	}
}
void updata(int k,int l,int r,int v)
{
	if(l<=t[k].l&&r>=t[k].r)
	{
		t[k].dat+=(long long)v*(t[k].r-t[k].l+1);
		t[k].lazy+=v;
		return ;
	}
	pushdown(k);
	int mid=(t[k].l+t[k].r)>>1;
	if(l<=mid)
	updata(k<<1,l,r,v);
	if(r>mid)
	updata(k<<1|1,l,r,v);
	pushup(k);
}
long long query(int k,int l,int r)
{
	if(l<=t[k].l&&r>=t[k].r)
	return t[k].dat;
	pushdown(k);
	int mid=(t[k].l+t[k].r)>>1;
	long long ans=0;
	if(l<=mid)
	ans+=query(k<<1,l,r);
	if(r>mid)
	ans+=query(k<<1|1,l,r);
	return ans;
}
int main()
{
	std::ios::sync_with_stdio(false);
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	cin>>a[i];
	build(1,1,n);
	for(int i=1;i<=m;i++)
	{
		int o;
		cin>>o;
		if(o==1)
		{
			int x,y,k;
			cin>>x>>y>>k;
			updata(1,x,y,k);
			continue;
		}
		else
		{
			int x,y;
			cin>>x>>y;
			cout<<query(1,x,y)<<'\n';
		}
	}
	return 0;
}
