```cpp
Dinic
#include <iostream>
#include <cstdio>
#include <algorithm>
#include <cstring>
#include <string>
#include <queue> 
using namespace std;
const long long inf=2005091500;
int n,m,s,t,u,v;
long long w,ans,d[520010];
int en=1,now[520010],first[520010]; 
struct edge {
	int e,next;
	long long val;
} ed[520010];

inline void add_edge(int u,int v,long long w) 
{
	ed[++en].e=v;
	ed[en].val=w;
	ed[en].next=first[u];
	first[u]=en;

	ed[++en].e=u;
	ed[en].val=0;
	ed[en].next=first[v];
	first[v]=en;
}

inline int bfs() {
	for(register int i=1;i<=n;i++) 
	d[i]=inf;
	queue<int> q;
	q.push(s);
	d[s]=0;
	now[s]=first[s];
	while(!q.empty()) 
	{
		int x=q.front();
		q.pop();
		for(register int i=first[x];i;i=ed[i].next)
		{
			int e=ed[i].e;
			if(ed[i].val>0&&d[e]==inf)
			{
				q.push(e);
				now[e]=first[e];
				d[e]=d[x]+1;
				if(e==t) return 1;
			}
		}
	}
	return 0;
}

inline int dfs(int x,long long sum) 
{
	if(x==t) return sum;
	long long k,res=0; 
	for(register int i=now[x];i&&sum;i=ed[i].next) 
	{
		now[x]=i;  
		int e=ed[i].e;
		if(ed[i].val>0&&(d[e]==d[x]+1)) 
		{
			k=dfs(e,min(sum,ed[i].val));
			if(k==0) d[e]=inf;  
			ed[i].val-=k;
			ed[i^1].val+=k;
			res+=k;
			sum-=k;  
		}
	}
	return res;
}

int main() 
{
	cin>>n>>m>>s>>t;
	for(register int i=1;i<=m;i++) 
	{
		cin>>u>>v>>w;
		add_edge(u,v,w);
	}
	while(bfs()) 
		ans+=dfs(s,inf); 
	cout<<ans<<endl;
	return 0;
}
