		int n,m,p;
		cin>>n>>m>>p;
		a[0]=1;
		for(int i=1;i<=p;i++)
		a[i]=(a[i-1]*i)%p;
		cout<<lucas(n+m,m,p)<<endl;
	}
	return 0;
}
