# 【解题报告】 POJ1050 To the Max

## 题目：[最大的和](https://www.acwing.com/problem/content/128/)（已翻译）

### 题意简述：

就是一个矩阵中找一个和最大的子矩阵

### 解题思路：

贪心，我们可以首先在输入的时候贪一遍心，然后我们可以一行一行地贪心，最终得到最后的正确结果

AC代码

```c++
#include <iostream>
#include <cstdio>
#include <algorithm>
using namespace std;
const int maxn=105;
int n;
int a[maxn][maxn],s[maxn][maxn];
int ans=-0x3f,nans;
bool check=false;
int max(int a,int b)
{
	return a>b? a:b;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			cin>>a[i][j];
			if(a[i][j]>=0)
			check=true;
			ans=max(ans,a[i][j]);
		}
	}
	if(!check)
	{
		cout<<ans<<endl;
		return 0;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		s[i][j]=s[i-1][j]+a[i][j];
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=i;j<=n;j++)
		{
			nans=0;
			for(int k=1;k<=n;k++)
			{
				nans+=s[j][k]-s[i-1][k];
				if(nans<0)
				nans=0;
				if(nans>ans)
				ans=nans;
			}
		}
	}
	cout<<ans<<endl;
	return 0;
}
```

# 【解题报告】 POJ2054 给树染色

## 题目：[Color a tree](https://www.acwing.com/problem/content/117/)(已翻译)

### 解题思路：

贪心

我们很容易想到从第一层开始，每次染权值最大的一个节点，但是我们可以构造出一个数，让一个权值很小的点下面有权值很大的节点，所以我们考虑的贪心思路是树中除了根节点外的权值最大的节点，它的父节点染色之后一定会被马上染色，所以我们可以将权值最大的点和它的父节点进行合并，合并得到的新点的权值是这两个点之和的平均值，这样就一直合并，直至合并到一个点的时候，我们就按照这个点合并的顺序染色就是正确的答案了。

AC代码

```c++
#include <iostream>
#include <cstdio>
using namespace std;
long long r,n;
long long i,j,now,ans,a,b,father;
struct node
{
	long long f,c,t;
	double w;
}num[1010];
long long find()
{
	long long ans=0;
	double maxn=0;
	for(int i=1;i<=n;i++)
	{
		if(i!=r&&num[i].w>maxn)
		{
			maxn=num[i].w;
			ans=i;
		}
	 } 
	 return ans;
}
int main()
{
	while(cin>>n>>r&&(n||r))
	{
		ans=0;
		for(int i=1;i<=n;i++)
		{
			cin>>num[i].c;
			num[i].w=num[i].c;
			num[i].t=1;
			ans+=num[i].c;
		}
		for(int i=1;i<=n-1;i++)
		{
			cin>>a>>b;
			num[b].f=a;
		}
		for(int i=1;i<=n-1;i++)
		{
			now=find();
			num[now].w=0;
			father=num[now].f;
			ans+=num[now].c*num[father].t;
			for(int j=1;j<=n;j++)
			{
				if(num[j].f==now)
				num[j].f=father;
			}
			num[father].c+=num[now].c;
			num[father].t+=num[now].t;
			num[father].w=(double)(num[father].c)/num[father].t;
		}
		cout<<ans<<endl;
	}
	return 0;
}
```

