# 【解题报告】 POJ3614 防晒

## 题目：[防晒](https://www.acwing.com/problem/content/112/)（已翻译）

### 解题思路：

模拟+贪心；

我们这道题是一道好的贪心的例题，我们只要对于每一头奶牛按照它们的minspf进行递减排序，然后在对于每一种防晒霜进行一次扫描，找出符合条件的spf值最大的防晒霜

但是会想到一点，我们需要将每一头奶牛的minspf和maxspf进行一一对应，所以我们可以使用结构体，然后自己在写一个比较函数，就可以让这两个数值一一对应，这样就方便多了

AC代码

```c++
#include <iostream>
#include <algorithm>
using namespace std;
const int maxn=2505;
int c,l,ans;
struct cow
{
	int minspf;
	int maxspf;
}a[maxn];
struct sc
{
	int spf;
	int cover;
}b[maxn];
int cmp(sc a,sc b)
{
    if(a.spf==b.spf)
    return a.cover>b.cover;
    return a.spf>b.spf;
}
int cmp2(cow a,cow b)
{
    if(a.minspf==b.minspf)
    return a.maxspf>b.maxspf;
    return a.minspf>b.minspf;
}
int main()
{
	cin>>c>>l;
	for(int i=1;i<=c;i++)
	cin>>a[i].minspf>>a[i].maxspf;
	sort(a+1,a+1+c,cmp2);
	for(int i=1;i<=l;i++)
	cin>>b[i].spf>>b[i].cover;
	sort(b+1,b+1+l,cmp);
	for(int i=1;i<=c;i++)
	{
		for(int j=1;j<=l;j++)
		{
			if(b[j].spf>=a[i].minspf&&b[j].spf<=a[i].maxspf&&b[j].cover)
			{
				ans++;
				b[j].cover--;
				break;
			}
		}
	}
	cout<<ans<<endl;
	return 0;
}
```

# 【解题报告】 天才ACM

## 题目：[天才ACM](https://www.acwing.com/problem/content/111/)

### 解题思路：

倍增算法

设p=1，r=l

求出r—r+p这一区间的校验值，如果校验值小于等于t，则r+=p，p*=2；

否则p/=2;

一直重复，直到p等于0的时候，r就是最终答案

AC代码

```c++
#include <iostream>
#include <cstdio>
#include <algorithm>
using namespace std;
const int maxn=500005;
long long t,tot;
long long n,m,k;
long long p[maxn];
long long f[maxn];
int l,r,mid,j;
long long min(long long a,long long b)
{
	return a<b? a:b;
}
bool check(int l,int r) 
{
    tot=0;
    long long sum=0;
    for(int i=l;i<=r;i++) 
	f[++tot]=p[i];
    sort(f+1,f+1+tot);
    for(int i=1;i<=m;i++) 
	{
        if (i>=(tot-i+1)) 
		break;
        sum+=(long long)(f[tot-i+1]-f[i])*(f[tot-i+1]-f[i]);
        if(sum>k)
		break;
    }
    if(sum>k)
	return false;
    return true;
}
bool cmp(int x,int y)
{
	return p[x]<p[y];
}
bool calc()
{
	long long sum=0;
	int ll=1,rr=tot;
	for(int i=1;i<=m;i++)
	{
		while(ll<rr&&f[ll]>mid)
		ll++;
		while(ll<rr&&f[rr]>mid)
		rr--;
		if(ll>=rr)
		break;
		sum+=(long long)(p[f[rr]]-p[f[ll]])*(p[f[rr]]-p[f[ll]]);
		if(sum>k)
		break;
		ll++;
		rr--;
	}
	return sum<=k;
}
void work()
{
		cin>>n>>m>>k;
		for(int i=1;i<=n;i++)
		cin>>p[i];
		int ans=0;
		for(int i=1;i<=n;i++)
		{
			for(j=1;i+(1<<j)-1<=n;j++)
			{
				if(!check(i,i+(1<<j)-1))
				break;
			}
			l=i+(1<<(j-1))-1;
			r=min(i+(1<<j)-1,n);
			tot=0;
			for(int k=i;k<=r;k++)
			f[++tot]=k;
			sort(f+1,f+tot+1,cmp);
			while(l<=r)
			{
				mid=(l+r)/2;
				if(calc())
				{
					i=mid;
					l=mid+1;
				}
				else r=mid-1;
			}
			ans++;
		}
		cout<<ans<<endl;
}
int main()
{
	cin>>t;
	while(t--)
	{
		work();
	}
	return 0;
}
```

# 【解题报告】POJ2299 超快速排序

## 题目：[超快速排序](https://www.acwing.com/problem/content/109/)（已翻译）

### 解题思路：

归并排序求逆序对

归并排序使我们众所周知的，我们只要在归并排序中计算每一个子序列中的逆序对数，我们就可以计算出总的逆序对数了，也就是
$$
cnt+=mid-i+1
$$
然后就完成了这道题

AC代码

```c++
#include <iostream>
#include <cstring>
using namespace std;
int n;
long long cnt;
const int maxn=500005;
long long a[maxn];
long long b[maxn];
void merge_sort(int l,int r)
{
    if(r>l)
    {
        int mid=(l+r)/2;
        int i=l; 
        int p=l,q=mid+1;
        merge_sort(l,mid);
        merge_sort(mid+1,r);
        while(p<=mid||q<=r)
        {
            if(q>r||(p<=mid&&a[p]<=a[q]))
            b[i++] = a[p++];
            else
            {
                b[i++]=a[q++];
                cnt+=mid-p+1;
            }
        }
        for(i=l;i<=r;i++)
        a[i]=b[i];
    }
}
int main()
{
	while(cin>>n&&n)
	{
		for(int i=1;i<=n;i++)
		cin>>a[i];
		cnt=0;
		merge_sort(1,n);
		cout<<cnt<<endl;
	}
	return 0;
}
```

