这道题就是一道标准的筛素数的题，因为它要访问多个数啊，不做素数筛不可以啊，所以经过努力，我写出了代码

```c++
#include <iostream>
#include <cstring>
using namespace std;
int v[10000005];//记录用
int n,m;
int p;
void primes(int n)//简单素数筛函数
{
	memset(v,0,sizeof(v));
	for(int i=2;i<=n;i++)
	{
		if(v[i])
		continue;
		for(int j=i;j<=n/i;j++)
		v[i*j]=1; 
	}
}
int main()
{
	cin>>n>>m;
	primes(n);//调用函数
	for(int i=1;i<=m;i++)
	{
		cin>>p;
		if(v[p])
		cout<<"No"<<endl;
		else 
		cout<<"Yes"<<endl;
	}
	return 0;
}
```

